    target: 'roll' | 'mod' | 'dc' | 'attribute';
    /** иҪ¬жҚўжҜ”дҫӢ (еҰӮ 1зӮ№иө„жәҗ = 1зӮ№жҠ•йӘ°з»“жһң) */
    ratio: number;
    /** еҪұе“Қж–№еҗ‘ (increase=еўһеҠ зӣ®ж ҮеҖј, decrease=еҮҸе°‘зӣ®ж ҮеҖј) */
    direction: 'increase' | 'decrease';
    /** иө„жәҗж“ҚдҪңж–№еҗ‘: subtract=ж¶ҲиҖ—/еҮҸе°‘иө„жәҗ(й»ҳи®Ө), add=еўһеҠ /зҙҜз§Ҝиө„жәҗ */
