  // еұһжҖ§йў„и®ҫз®ЎзҗҶеҷЁ
  const AttributePresetManager = (() => {
    let _cache = null;

    return {
      // иҺ·еҸ–жүҖжңүйў„и®ҫпјҲеҶ…зҪ® + иҮӘе®ҡд№үпјҢиҮӘеҠЁжЈҖжөӢе№¶жӣҙж–°зүҲжң¬пјү
      getAllPresets() {
        const stored = Store.get(STORAGE_KEY_ATTRIBUTE_PRESETS, []);
        // иҮӘеҠЁжЈҖжөӢе№¶жӣҙж–°жүҖжңүиҮӘе®ҡд№үйў„и®ҫзҡ„зүҲжң¬пјҲжҜҸж¬Ўи°ғз”ЁйғҪжЈҖжөӢпјҢдёҚдҫқиө–зј“еӯҳпјү
        let needsSave = false;
        stored.forEach(preset => {
          const presetVersion = preset.version || '0.0.0';
          if (compareVersion(presetVersion, PRESET_FORMAT_VERSION) < 0) {
            console.log(
              `[DICE]AttributePresetManager жЈҖжөӢеҲ°йў„и®ҫ "${preset.name}" зүҲжң¬иҫғж—§ (${presetVersion})пјҢиҮӘеҠЁжӣҙж–°еҲ° ${PRESET_FORMAT_VERSION}`,
            );
            preset.version = PRESET_FORMAT_VERSION;
            needsSave = true;
          }
        });
        if (needsSave) {
          Store.set(STORAGE_KEY_ATTRIBUTE_PRESETS, stored);
          // жё…йҷӨзј“еӯҳпјҢзЎ®дҝқдёӢж¬ЎиҺ·еҸ–ж—¶дҪҝз”Ёжӣҙж–°еҗҺзҡ„ж•°жҚ®
          _cache = null;
        }
        // еҸӘжңүеңЁжІЎжңүжӣҙж–°ж—¶жүҚдҪҝз”Ёзј“еӯҳ
        if (!needsSave && _cache) {
          return _cache;
        }
        _cache = [...BUILTIN_ATTRIBUTE_PRESETS, ...stored];
        return _cache;
      },

      // иҺ·еҸ–еҪ“еүҚжҝҖжҙ»зҡ„йў„и®ҫпјҲnull = дҪҝз”Ёй»ҳи®ӨйҖ»иҫ‘пјү
      getActivePreset() {
        const activeId = Store.get(STORAGE_KEY_ACTIVE_ATTR_PRESET, null);
        if (!activeId) return null;
        return this.getAllPresets().find(p => p.id === activeId) || null;
      },

      // и®ҫзҪ®жҝҖжҙ»зҡ„йў„и®ҫ
      setActivePreset(id) {
        try {
          // еҰӮжһңidжҳҜз©әеӯ—з¬ҰдёІпјҢи®ҫзҪ®дёәnull
          const finalId = id === '' || id === undefined ? null : id;
          Store.set(STORAGE_KEY_ACTIVE_ATTR_PRESET, finalId);
          // жё…йҷӨзј“еӯҳпјҢзЎ®дҝқдёӢж¬ЎиҺ·еҸ–ж—¶жҳҜжңҖж–°зҡ„
          _cache = null;
          console.log('[DICE]AttributePresetManager еҲҮжҚўйў„и®ҫ:', finalId);
          // е»¶иҝҹи°ғз”Ёд»ҘзЎ®дҝқеҮҪж•°е·Іе®ҡд№үпјҲеҮҪж•°еңЁ AttributePresetManager д№ӢеҗҺе®ҡд№үпјү
          setTimeout(() => {
            if (typeof updateTemplateForActivePreset === 'function') {
              updateTemplateForActivePreset(finalId);
            }
          }, 0);
          return true;
        } catch (err) {
          console.error('[DICE]AttributePresetManager и®ҫзҪ®йў„и®ҫеӨұиҙҘ:', err);
          return false;
        }
      },

      // еҲӣе»әиҮӘе®ҡд№үйў„и®ҫ
      createPreset(preset) {
        const stored = Store.get(STORAGE_KEY_ATTRIBUTE_PRESETS, []);
        const newPreset = {
          ...preset,
          id: preset.id || 'custom_' + Date.now(),
          builtin: false,
          version: preset.version || PRESET_FORMAT_VERSION,
          createdAt: new Date().toISOString(),
        };
        stored.push(newPreset);
        Store.set(STORAGE_KEY_ATTRIBUTE_PRESETS, stored);
        _cache = null;
        console.log('[DICE]AttributePresetManager еҲӣе»әйў„и®ҫ:', newPreset.name);
        return newPreset;
      },

      // жӣҙж–°иҮӘе®ҡд№үйў„и®ҫ
      updatePreset(id, updates) {
        const stored = Store.get(STORAGE_KEY_ATTRIBUTE_PRESETS, []);
        const index = stored.findIndex(p => p.id === id);
        if (index < 0) return false;
        stored[index] = { ...stored[index], ...updates };
        Store.set(STORAGE_KEY_ATTRIBUTE_PRESETS, stored);
        _cache = null;
        console.log('[DICE]AttributePresetManager жӣҙж–°йў„и®ҫ:', id);
        return true;
      },

      // еҲ йҷӨиҮӘе®ҡд№үйў„и®ҫ
      deletePreset(id) {
        const stored = Store.get(STORAGE_KEY_ATTRIBUTE_PRESETS, []);
        const filtered = stored.filter(p => p.id !== id);
        if (filtered.length === stored.length) return false;
        Store.set(STORAGE_KEY_ATTRIBUTE_PRESETS, filtered);
        _cache = null;
        // еҰӮжһңеҲ йҷӨзҡ„жҳҜжҝҖжҙ»йў„и®ҫпјҢжё…йҷӨжҝҖжҙ»зҠ¶жҖҒ
        if (Store.get(STORAGE_KEY_ACTIVE_ATTR_PRESET) === id) {
          Store.set(STORAGE_KEY_ACTIVE_ATTR_PRESET, null);
        }
        console.log('[DICE]AttributePresetManager еҲ йҷӨйў„и®ҫ:', id);
        return true;
      },

      // еҜјеҮәйў„и®ҫдёә JSON
      exportPreset(id) {
        const preset = this.getAllPresets().find(p => p.id === id);
        if (!preset) return null;
        const exported = {
          format: 'acu_attr_preset_v1',
          version: PRESET_FORMAT_VERSION,
          ...preset,
        };
        delete exported.builtin; // еҜјеҮәж—¶з§»йҷӨеҶ…зҪ®ж Үи®°
        return JSON.stringify(exported, null, 2);
      },

      // д»Һ JSON еҜје…Ҙйў„и®ҫ
      importPreset(jsonStr, autoUpdate = false) {
        try {
          const data = JSON.parse(jsonStr);

          // ж ЎйӘҢж јејҸ
          if (data.format !== 'acu_attr_preset_v1') {
            throw new Error('дёҚж”ҜжҢҒзҡ„йў„и®ҫж јејҸ');
          }

          // еҹәжң¬ж ЎйӘҢ
          if (!data.name || !data.baseAttributes || !Array.isArray(data.baseAttributes)) {
            throw new Error('йў„и®ҫж•°жҚ®дёҚе®Ңж•ҙ');
          }

          const importedVersion = data.version || '0.0.0';
          const needsUpdate = compareVersion(importedVersion, PRESET_FORMAT_VERSION) < 0;

          // з”ҹжҲҗж–°IDйҒҝе…ҚеҶІзӘҒ
          const imported = {
            ...data,
            id: 'imported_' + Date.now(),
            builtin: false,
            version: autoUpdate && needsUpdate ? PRESET_FORMAT_VERSION : importedVersion,
            createdAt: new Date().toISOString(),
          };

          const result = this.createPreset(imported);
          if (result && needsUpdate && !autoUpdate) {
            console.warn(
              `[DICE]AttributePresetManager еҜје…Ҙзҡ„йў„и®ҫ "${result.name}" зүҲжң¬иҫғж—§ (${importedVersion})пјҢе»әи®®жӣҙж–°еҲ° ${PRESET_FORMAT_VERSION}`,
            );
          }
          return result;
        } catch (e) {
          console.error('[DICE]AttributePresetManager еҜје…ҘеӨұиҙҘ:', e);
          return null;
        }
      },

      // жё…йҷӨзј“еӯҳ
      clearCache() {
        _cache = null;
      },
    };
  })();

  // ========================================
  // й«ҳзә§йӘ°еӯҗйў„и®ҫз®ЎзҗҶеҷЁ
  // ========================================

  const STORAGE_KEY_ACTIVE_ADVANCED_PRESET = 'acu_active_advanced_preset';

  // й«ҳзә§йӘ°еӯҗйў„и®ҫз®ЎзҗҶеҷЁ
  const AdvancedDicePresetManager = (() => {
    let _cache = null;

    const getBuiltinPresetVisibilityMap = (): Record<string, boolean> => {
      const stored = Store.get(STORAGE_KEY_BUILTIN_PRESET_VISIBILITY, {});
      if (!stored || typeof stored !== 'object') return {};
      return stored as Record<string, boolean>;
    };

    const getBuiltinPresetOrderMap = (): Record<string, number> => {
      const stored = Store.get(STORAGE_KEY_BUILTIN_PRESET_ORDER, {});
      if (!stored || typeof stored !== 'object') return {};
      return stored as Record<string, number>;
    };

    return {
      // иҺ·еҸ–жүҖжңүйў„и®ҫпјҲеҶ…зҪ® + иҮӘе®ҡд№үпјү
      getAllPresets() {
        const stored = Store.get(STORAGE_KEY_ADVANCED_PRESETS, []);
        // иҮӘеҠЁжЈҖжөӢе№¶жӣҙж–°жүҖжңүиҮӘе®ҡд№үйў„и®ҫзҡ„зүҲжң¬
        let needsSave = false;
        stored.forEach(preset => {
          const presetVersion = preset.version || '0.0.0';
          if (compareVersion(presetVersion, PRESET_FORMAT_VERSION) < 0) {
            console.log(
              `[DICE]AdvancedDicePresetManager жЈҖжөӢеҲ°йў„и®ҫ "${preset.name}" зүҲжң¬иҫғж—§ (${presetVersion})пјҢиҮӘеҠЁжӣҙж–°еҲ° ${PRESET_FORMAT_VERSION}`,
            );
            preset.version = PRESET_FORMAT_VERSION;
            needsSave = true;
          }
        });
        if (needsSave) {
          Store.set(STORAGE_KEY_ADVANCED_PRESETS, stored);
          _cache = null;
        }
        // еҸӘжңүеңЁжІЎжңүжӣҙж–°ж—¶жүҚдҪҝз”Ёзј“еӯҳ
        if (!needsSave && _cache) {
          return _cache;
        }

        // еЎ«е……й»ҳи®ӨеҖје№¶еҗҲе№¶
        const builtinVisibilityMap = getBuiltinPresetVisibilityMap();
        const builtinOrderMap = getBuiltinPresetOrderMap();
        const processedBuiltin = BUILTIN_ADVANCED_PRESETS.map((p, index) => ({
          ...p,
          visible: builtinVisibilityMap[p.id] ?? p.visible ?? true,
          order: builtinOrderMap[p.id] ?? p.order ?? index,
        }));

        const processedCustom = stored.map(p => ({
          ...p,
          visible: p.visible ?? false,
          order: p.order ?? 999,
        }));

        _cache = [...processedBuiltin, ...processedCustom];
        return _cache;
      },

      // иҺ·еҸ–еҪ“еүҚжҝҖжҙ»зҡ„йў„и®ҫпјҲnull = жңӘжҝҖжҙ»пјү
      getActivePreset() {
        const activeId = Store.get(STORAGE_KEY_ACTIVE_ADVANCED_PRESET, null);
        if (!activeId) return null;
        return this.getAllPresets().find(p => p.id === activeId) || null;
      },

      // и®ҫзҪ®жҝҖжҙ»зҡ„йў„и®ҫ
      setActivePreset(id) {
        try {
          const finalId = id === '' || id === undefined ? null : id;
          Store.set(STORAGE_KEY_ACTIVE_ADVANCED_PRESET, finalId);
          _cache = null;
          console.log('[DICE]AdvancedDicePresetManager еҲҮжҚўйў„и®ҫ:', finalId);
          return true;
        } catch (err) {
          console.error('[DICE]AdvancedDicePresetManager и®ҫзҪ®йў„и®ҫеӨұиҙҘ:', err);
          return false;
        }
      },

      setBuiltinPresetVisibility(id, visible) {
        try {
          const map = getBuiltinPresetVisibilityMap();
          map[id] = visible;
          Store.set(STORAGE_KEY_BUILTIN_PRESET_VISIBILITY, map);
          _cache = null;
          return true;
        } catch (err) {
          console.error('[DICE]AdvancedDicePresetManager и®ҫзҪ®еҶ…зҪ®йў„и®ҫжҳҫзӨәзҠ¶жҖҒеӨұиҙҘ:', err);
          return false;
        }
      },

      setPresetOrder(id, order) {
        try {
          if (BUILTIN_ADVANCED_PRESETS.some(p => p.id === id)) {
            const map = getBuiltinPresetOrderMap();
            map[id] = order;
            Store.set(STORAGE_KEY_BUILTIN_PRESET_ORDER, map);
            _cache = null;
            return true;
          }
          return this.updatePreset(id, { order });
        } catch (err) {
          console.error('[DICE]AdvancedDicePresetManager и®ҫзҪ®йў„и®ҫжҺ’еәҸеӨұиҙҘ:', err);
          return false;
        }
      },

      // еҲӣе»әиҮӘе®ҡд№үйў„и®ҫ
      createPreset(preset) {
        const stored = Store.get(STORAGE_KEY_ADVANCED_PRESETS, []);
        const newPreset = {
          ...preset,
          id: preset.id || 'custom_' + Date.now(),
          kind: 'advanced',
          builtin: false,
          version: preset.version || PRESET_FORMAT_VERSION,
          createdAt: new Date().toISOString(),
        };
        stored.push(newPreset);
        Store.set(STORAGE_KEY_ADVANCED_PRESETS, stored);
        _cache = null;
        console.log('[DICE]AdvancedDicePresetManager еҲӣе»әйў„и®ҫ:', newPreset.name);
        return newPreset;
      },

      // жӣҙж–°иҮӘе®ҡд№үйў„и®ҫ
      updatePreset(id, updates) {
        // зҰҒжӯўдҝ®ж”№еҶ…зҪ®йў„и®ҫ
        if (BUILTIN_ADVANCED_PRESETS.some(p => p.id === id)) {
          console.error('[DICE]AdvancedDicePresetManager дёҚиғҪдҝ®ж”№еҶ…зҪ®йў„и®ҫ:', id);
          throw new Error('дёҚиғҪдҝ®ж”№еҶ…зҪ®йў„и®ҫ');
        }
        const stored = Store.get(STORAGE_KEY_ADVANCED_PRESETS, []);
        const index = stored.findIndex(p => p.id === id);
        if (index < 0) return false;
        stored[index] = { ...stored[index], ...updates, id }; // дҝқжҢҒIDдёҚеҸҳ
        Store.set(STORAGE_KEY_ADVANCED_PRESETS, stored);
        _cache = null;
        console.log('[DICE]AdvancedDicePresetManager жӣҙж–°йў„и®ҫ:', id);
        return true;
      },

      // еҲ йҷӨиҮӘе®ҡд№үйў„и®ҫ
      deletePreset(id) {
        // зҰҒжӯўеҲ йҷӨеҶ…зҪ®йў„и®ҫ
        if (BUILTIN_ADVANCED_PRESETS.some(p => p.id === id)) {
          console.error('[DICE]AdvancedDicePresetManager дёҚиғҪеҲ йҷӨеҶ…зҪ®йў„и®ҫ:', id);
          throw new Error('дёҚиғҪеҲ йҷӨеҶ…зҪ®йў„и®ҫ');
        }
        const stored = Store.get(STORAGE_KEY_ADVANCED_PRESETS, []);
        const filtered = stored.filter(p => p.id !== id);
        if (filtered.length === stored.length) return false;
        Store.set(STORAGE_KEY_ADVANCED_PRESETS, filtered);
        _cache = null;
        // еҰӮжһңеҲ йҷӨзҡ„жҳҜжҝҖжҙ»йў„и®ҫпјҢжё…йҷӨжҝҖжҙ»зҠ¶жҖҒ
        if (Store.get(STORAGE_KEY_ACTIVE_ADVANCED_PRESET) === id) {
          Store.set(STORAGE_KEY_ACTIVE_ADVANCED_PRESET, null);
        }
        console.log('[DICE]AdvancedDicePresetManager еҲ йҷӨйў„и®ҫ:', id);
        return true;
      },

      // еҜјеҮәйў„и®ҫдёә JSON
      exportPreset(id) {
        const preset = this.getAllPresets().find(p => p.id === id);
        if (!preset) return null;
        const exported = {
          kind: 'advanced',
          version: PRESET_FORMAT_VERSION,
          ...preset,
        };
        delete exported.builtin; // еҜјеҮәж—¶з§»йҷӨеҶ…зҪ®ж Үи®°
        return JSON.stringify(exported, null, 2);
      },

      // д»Һ JSON еҜје…Ҙйў„и®ҫ
      importPreset(jsonStr) {
        try {
          const data = JSON.parse(jsonStr);

          // ж ЎйӘҢж јејҸ
          if (data.kind !== 'advanced') {
            throw new Error('дёҚж”ҜжҢҒзҡ„йў„и®ҫж јејҸ');
          }

          // еҹәжң¬ж ЎйӘҢ
          if (!data.name || !data.diceExpression) {
            throw new Error('йў„и®ҫж•°жҚ®дёҚе®Ңж•ҙ: зјәе°‘еҗҚз§°жҲ–йӘ°еӯҗиЎЁиҫҫејҸ');
          }

          // ж ЎйӘҢеҲӨе®ҡжқЎд»¶пјҡеҝ…йЎ»жңү outcomes
          if (!Array.isArray(data.outcomes) || data.outcomes.length === 0) {
            throw new Error('йў„и®ҫж•°жҚ®дёҚе®Ңж•ҙ: зјәе°‘ outcomes еҲӨе®ҡжқЎд»¶');
          }

          const importedVersion = data.version || '0.0.0';
          const needsUpdate = compareVersion(importedVersion, PRESET_FORMAT_VERSION) < 0;

          // ж•°жҚ®иҝҒз§»пјҡеҗҲе№¶ж—§зүҲ UI еӯ—ж®ө
          if (data.ui) {
            if (data.ui.attributeLabel && data.attribute) data.attribute.label = data.ui.attributeLabel;
            if (data.ui.dcLabel && data.dc) data.dc.label = data.ui.dcLabel;
            delete data.ui;
          }

          // з”ҹжҲҗж–°IDйҒҝе…ҚеҶІзӘҒ
          const imported = {
            ...data,
            id: 'imported_' + Date.now(),
            kind: 'advanced',
            builtin: false,
            version: PRESET_FORMAT_VERSION,
            createdAt: new Date().toISOString(),
          };

          const result = this.createPreset(imported);
          if (result && needsUpdate) {
            console.warn(
              `[DICE]AdvancedDicePresetManager еҜје…Ҙзҡ„йў„и®ҫ "${result.name}" зүҲжң¬иҫғж—§ (${importedVersion})пјҢе·ІиҮӘеҠЁжӣҙж–°еҲ° ${PRESET_FORMAT_VERSION}`,
            );
          }
          return result;
        } catch (e) {
          console.error('[DICE]AdvancedDicePresetManager еҜје…ҘеӨұиҙҘ:', e);
          return null;
        }
      },

      // жё…йҷӨзј“еӯҳ
      clearCache() {
        _cache = null;
      },

      /**
       * жЈҖжҹҘйў„и®ҫжҳҜеҗҰж”ҜжҢҒеҜ№жҠ—жЈҖе®ҡ
       * @param preset йў„и®ҫеҜ№иұЎжҲ–йў„и®ҫID
       * @returns true иЎЁзӨәж”ҜжҢҒеҜ№жҠ—жЈҖе®ҡпјҢfalse иЎЁзӨәдёҚж”ҜжҢҒ
       */
      supportsContest(preset: AdvancedDicePreset | string | null | undefined): boolean {
        if (!preset) return true; // ж— йў„и®ҫж—¶пјҲиҮӘе®ҡд№үжЁЎејҸпјүй»ҳи®Өж”ҜжҢҒ

        const presetObj = typeof preset === 'string' ? this.getAllPresets().find(p => p.id === preset) : preset;
        if (!presetObj) return true; // жүҫдёҚеҲ°йў„и®ҫж—¶й»ҳи®Өж”ҜжҢҒ

        // жЈҖжҹҘ contestRule.disabled ж Үеҝ—
        return !(presetObj.contestRule?.disabled === true);
      },
    };
  })();

  // ========================================
  // йў„и®ҫеҲҮжҚўж—¶жӣҙж–°иЎЁж јжЁЎжқҝ
  // ========================================

  /**
   * ж №жҚ®ж•°еҖјиҢғеӣҙеҠЁжҖҒз”ҹжҲҗеұһжҖ§ж Үе°әжҸҸиҝ°пјҲеҢ…еҗ«еҹәеҮҶиҜҙжҳҺпјү
   * е°ҶиҢғеӣҙжҢүжҜ”дҫӢеҲ’еҲҶдёә6дёӘеҢәй—ҙпјҡиғҪеҠӣзјәеӨұ/ејұйЎ№/е№іеқҮ/зІҫиӢұ/жһҒйҷҗ/з ҙж ј
   * @param min иҢғеӣҙжңҖе°ҸеҖј
   * @param max иҢғеӣҙжңҖеӨ§еҖј
   * @returns е®Ңж•ҙзҡ„еұһжҖ§ж Үе°әжҸҸиҝ°еӯ—з¬ҰдёІпјҲеҢ…еҗ«ж Үе°әе’ҢеҹәеҮҶиҜҙжҳҺпјү
   */
  const generateAttributeScale = (min: number, max: number): string => {
    const range = max - min;

    // и®Ўз®—еҗ„еҢәй—ҙзҡ„иҫ№з•ҢеҖјпјҲеҗ‘дёӢеҸ–ж•ҙпјү
    const threshold1 = Math.floor(min + range * 0.1); // иғҪеҠӣзјәеӨұдёҠйҷҗ
    const threshold2 = Math.floor(min + range * 0.4); // ејұйЎ№дёҠйҷҗ
    const threshold3 = Math.floor(min + range * 0.6); // е№іеқҮдёҠйҷҗ
    const threshold4 = Math.floor(min + range * 0.8); // зІҫиӢұдёҠйҷҗ
    const threshold5 = Math.floor(min + range * 0.9); // жһҒйҷҗдёҠйҷҗ

    // з”ҹжҲҗж Үе°әеӯ—з¬ҰдёІпјҢеӨ„зҗҶиҫ№з•Ңжғ…еҶөпјҲйҒҝе…ҚеҮәзҺ° "3-3" иҝҷж ·зҡ„еҢәй—ҙпјү
    const formatRange = (start: number, end: number): string => {
      if (start === end) return `${start}`;
      return `${start}-${end}`;
    };

    const scales = [
      `${formatRange(min, threshold1)}:иғҪеҠӣзјәеӨұ`,
      `${formatRange(threshold1 + 1, threshold2)}:ејұйЎ№`,
      `${formatRange(threshold2 + 1, threshold3)}:е№іеқҮ`,
      `${formatRange(threshold3 + 1, threshold4)}:зІҫиӢұ`,
      `${formatRange(threshold4 + 1, threshold5)}:жһҒйҷҗ`,
      `${formatRange(threshold5 + 1, max)}:з ҙж ј`,
    ];

    const scaleStr = scales.join(' | ');

    // и®Ўз®—еҹәеҮҶиҜҙжҳҺдёӯзҡ„еҠЁжҖҒж•°еҖј
    // "иҒҡйӣҶеңЁ40-60" вҶ’ е№іеқҮеҢәй—ҙ
    // "90+е‘Ҳж–ӯеҙ–ејҸзЁҖзјә" вҶ’ жһҒйҷҗеҢәй—ҙиө·зӮ№
    // "йҮҚдјӨвҶ’0-10" вҶ’ иғҪеҠӣзјәеӨұеҢәй—ҙ
    // "иӮҫдёҠи…әзҙ вҶ’80" вҶ’ зІҫиӢұеҢәй—ҙзҡ„й«ҳз«ҜеҖј
    const avgStart = threshold2 + 1;
    const avgEnd = threshold3;
    const rareThreshold = threshold5 + 1; // з ҙж јеҢәй—ҙиө·зӮ№
    const debuffRange = formatRange(min, threshold1); // иғҪеҠӣзјәеӨұеҢәй—ҙ
    const buffRange = formatRange(threshold4 + 1, threshold5); // зІҫиӢұеҢәй—ҙдёҠйҷҗ

    const baseDescription = `еҹәеҮҶ: ж•°еҖје‘ҲжҢҮж•°еўһй•ҝпјӣеҲҶеёғе‘Ҳй•ҝе°ҫзҠ¶(з»қеӨ§еӨҡж•°иҒҡйӣҶеңЁ${avgStart}-${avgEnd}пјҢ${rareThreshold}+е‘Ҳж–ӯеҙ–ејҸзЁҖзјә)пјҢдҫқи§’иүІ[иә«д»ҪиғҢжҷҜ]з”ҹжҲҗпјҢеҪ“еүҚеҖјеҸ—[еҪ“еүҚзҠ¶жҖҒ]дҝ®жӯЈгҖӮеҰӮ:йҮҚдјӨвҶ’${debuffRange}; иӮҫдёҠи…әзҙ вҶ’${buffRange}`;

    return `${scaleStr}гҖӮ${baseDescription}`;
  };

  // й»ҳи®Өи§„еҲҷзҡ„зү№жңүеұһжҖ§жЁЎжқҝеҶ…е®№пјҲз”ЁдәҺжҒўеӨҚпјү
  const DEFAULT_SPECIAL_ATTR_TEMPLATE = {
    // дё»и§’дҝЎжҒҜиЎЁе’ҢйҮҚиҰҒдәәзү©иЎЁз»ҹдёҖзҡ„й»ҳи®ӨеҶ…е®№
    range: [0, 100] as [number, number],
    // й»ҳи®ӨзӨәдҫӢпјҲеҲҶеҸ·еҲҶйҡ”ж јејҸпјү
    example: 'зҲҶиЈӮйӯ”жі•:85; ж—¶й—ҙеӣһжәҜ:70; и¶…з”өзЈҒзӮ®:90',
  };

  // й»ҳи®Өи§„еҲҷзҡ„иҷҡжӢҹйў„и®ҫе®ҡд№үпјҲе…ӯз»ҙеұһжҖ§зҷҫеҲҶеҲ¶пјү
  const DEFAULT_VIRTUAL_PRESET = {
    id: '__default__',
    name: 'е…ӯз»ҙеұһжҖ§зҷҫеҲҶеҲ¶',
    baseAttributes: ['еҠӣйҮҸ', 'ж•ҸжҚ·', 'дҪ“иҙЁ', 'жҷәеҠӣ', 'ж„ҹзҹҘ', 'йӯ…еҠӣ'].map(name => ({
      name,
      formula: '3d6*5',
      range: [5, 95] as [number, number],
      modifier: '1d10-5',
    })),
    specialAttributes: [] as { name: string; formula: string; range: [number, number]; modifier: string }[],
  };

  /**
   * жӣҝжҚўж ҮзӯҫеҶ…е®№зҡ„йҖҡз”ЁеҮҪж•°пјҲж”ҜжҢҒеӨҡиЎҢеҶ…е®№пјү
   * @param text еҺҹе§Ӣж–Үжң¬
   * @param tag ж ҮзӯҫеҗҚпјҲдёӯж–Үж ҮзӯҫеҰӮ "еұһжҖ§и§„еҲҷ"пјү
   * @param content ж–°еҶ…е®№
   */
  const replaceTag = (text: string, tag: string, content: string): string => {
    // дҪҝз”Ё [\s\S]* еҢ№й…Қд»»ж„Ҹеӯ—з¬ҰпјҲеҢ…жӢ¬жҚўиЎҢпјү
    const regex = new RegExp(`<${tag}>[\\s\\S]*?</${tag}>`, 'g');
    return text.replace(regex, `<${tag}>\n${content}\n</${tag}>`);
  };

  /**
   * ж №жҚ®жҝҖжҙ»зҡ„еұһжҖ§йў„и®ҫжӣҙж–°иЎЁж јжЁЎжқҝдёӯзҡ„зӨәдҫӢе’ҢиҢғеӣҙ
   * @param presetId йў„и®ҫIDпјҢnull иЎЁзӨәдҪҝз”Ёй»ҳи®ӨйҖ»иҫ‘
   */
  const updateTemplateForActivePreset = (presetId: string | null): void => {
    // 1. иҺ·еҸ–йў„и®ҫеҜ№иұЎпјҲй»ҳи®Өи§„еҲҷдҪҝз”ЁиҷҡжӢҹйў„и®ҫпјҢзЎ®дҝқз»ҹдёҖеӨ„зҗҶи·Ҝеҫ„пјү
    type AttributePreset = (typeof BUILTIN_ATTRIBUTE_PRESETS)[number];
    let preset: AttributePreset;
    if (presetId === null || presetId === '__default__') {
      // дҪҝз”ЁиҷҡжӢҹй»ҳи®Өйў„и®ҫ
      preset = DEFAULT_VIRTUAL_PRESET as AttributePreset;
    } else {
      const found = AttributePresetManager.getAllPresets().find((p: AttributePreset) => p.id === presetId);
      preset = found || (DEFAULT_VIRTUAL_PRESET as AttributePreset);
    }

    // 2. з”ҹжҲҗйҡҸжңәеұһжҖ§еҖј
    // жіЁж„ҸпјҡеҜ№дәҺй»ҳи®Өи§„еҲҷпјҢдј е…Ҙ null д»ҘдҪҝз”Ё generateRPGAttributes зҡ„еҶ…зҪ®й»ҳи®ӨйҖ»иҫ‘
    const attrs = generateRPGAttributes(presetId === null || presetId === '__default__' ? null : preset);
    // attrs = { base: {...}, special: {...} }

    // 3. и®Ўз®—ж•°еҖјиҢғеӣҙпјҲз»ҹдёҖд»Һ preset еҜ№иұЎиҜ»еҸ–пјү
    let baseRangeMin = 0;
    let baseRangeMax = 100;
    let specialRangeMin = 0;
    let specialRangeMax = 100;

    // еҹәзЎҖеұһжҖ§иҢғеӣҙпјҡеҸ–жүҖжңү baseAttributes.range зҡ„ min/max
    if (preset.baseAttributes && preset.baseAttributes.length > 0) {
      const baseRanges = preset.baseAttributes.map(attr => attr.range);
      baseRangeMin = Math.min(...baseRanges.map(r => r[0]));
      baseRangeMax = Math.max(...baseRanges.map(r => r[1]));
    }
    // зү№жңүеұһжҖ§иҢғеӣҙпјҡеҸ–жүҖжңү specialAttributes.range зҡ„ min/max
    if (preset.specialAttributes && preset.specialAttributes.length > 0) {
      const specialRanges = preset.specialAttributes.map(attr => attr.range);
      specialRangeMin = Math.min(...specialRanges.map(r => r[0]));
      specialRangeMax = Math.max(...specialRanges.map(r => r[1]));
    }

    // 4. иҺ·еҸ–з”ҹжҲҗзҡ„еұһжҖ§ж•°жҚ®
    const baseEntries = Object.entries(attrs.base as Record<string, number>);
    const specialEntries = Object.entries(attrs.special as Record<string, number>);

    // 5. иҺ·еҸ–ж•°жҚ®еә“ API е№¶иҜ»еҸ–жЁЎжқҝ
    const dbApi = getCore().getDB();
    if (!dbApi || typeof dbApi.getTableTemplate !== 'function') {
      console.warn('[DICE] updateTemplateForActivePreset: ж•°жҚ®еә“ API дёҚеҸҜз”ЁпјҢи·іиҝҮжӣҙж–°');
      return;
    }

    const template = dbApi.getTableTemplate();
    if (!template) {
      console.warn('[DICE] updateTemplateForActivePreset: ж— жі•иҺ·еҸ–иЎЁж јжЁЎжқҝпјҢи·іиҝҮжӣҙж–°');
      return;
    }

    // 6. з”ҹжҲҗеұһжҖ§ж Үе°әпјҲеҹәдәҺеҹәзЎҖеұһжҖ§иҢғеӣҙпјҢдёҚеҗ«йҮҚеӨҚзҡ„еҹәеҮҶиҜҙжҳҺпјү
    const attributeScaleStr = generateAttributeScale(baseRangeMin, baseRangeMax);

    // 7. жһ„е»әе®Ңж•ҙзҡ„ <еұһжҖ§и§„еҲҷ> еҶ…е®№еқ—
    const baseRangeStr = `[${baseRangeMin},${baseRangeMax}]`;
    const specialRangeStr =
      specialEntries.length > 0
        ? `[${specialRangeMin},${specialRangeMax}]`
        : `[${DEFAULT_SPECIAL_ATTR_TEMPLATE.range[0]},${DEFAULT_SPECIAL_ATTR_TEMPLATE.range[1]}]`;

    // еҹәзЎҖеұһжҖ§зӨәдҫӢпјҲеҲҶеҸ·еҲҶйҡ”ж јејҸпјү
    const baseExampleStr =
      baseEntries.length > 0
        ? baseEntries.map(([name, value]) => `${name}:${value}`).join('; ')
        : 'еҠӣйҮҸ:35; ж•ҸжҚ·:50; дҪ“иҙЁ:52; жҷәеҠӣ:35; ж„ҹзҹҘ:40; йӯ…еҠӣ:64';

    // зү№жңүеұһжҖ§зӨәдҫӢпјҲеҲҶеҸ·еҲҶйҡ”ж јејҸпјү
    const specialExampleStr =
      specialEntries.length > 0
        ? specialEntries.map(([name, value]) => `${name}:${value}`).join('; ')
        : DEFAULT_SPECIAL_ATTR_TEMPLATE.example;

    // жһ„е»әе®Ңж•ҙзҡ„еұһжҖ§и§„еҲҷеҶ…е®№
    const attributeRulesContent = `еҹәзЎҖеұһжҖ§: "{еҹәзЎҖеұһжҖ§}:{ж•°еҖј}"пјҢж•°еҖјиҢғеӣҙ${baseRangeStr}
зӨәдҫӢ: "${baseExampleStr}"

зү№жңүеұһжҖ§: и§’иүІзҡ„зү№ж®ҠиғҪеҠӣдёҺжҠҖиғҪпјҢдҪ“зҺ°дё–з•Ңи§Ӯзү№иүІдёҺдёӘдҪ“е·®ејӮгҖӮ
ж јејҸ: "{зү№жңүеұһжҖ§}:{ж•°еҖј}"пјҢж•°еҖјиҢғеӣҙ${specialRangeStr}пјҢж•°еҖјд»ЈиЎЁжҲҗеҠҹжҰӮзҺҮ
зӨәдҫӢ: "${specialExampleStr}"

гҖҗеұһжҖ§ж Үе°әгҖ‘
${attributeScaleStr}`;

    let modified = false;

    // 7.5 жЈҖжөӢж—§зүҲжЁЎжқҝж јејҸпјҲзјәе°‘ <еұһжҖ§и§„еҲҷ> ж Үзӯҫпјү
    const checkTemplateFormat = (note: string | undefined, sheetName: string): void => {
      if (!note) return;
      if (!note.includes('<еұһжҖ§и§„еҲҷ>')) {
        console.warn(
          `[DICE] ${sheetName} дҪҝз”Ёж—§зүҲжЁЎжқҝж јејҸпјҢзјәе°‘ <еұһжҖ§и§„еҲҷ> ж ҮзӯҫгҖӮ` +
            `еұһжҖ§йў„и®ҫеҲҮжҚўеҠҹиғҪж— жі•жӯЈеёёе·ҘдҪңгҖӮиҜ·жүӢеҠЁжӣҙж–°жЁЎжқҝд»Ҙж·»еҠ  <еұһжҖ§и§„еҲҷ>...</еұһжҖ§и§„еҲҷ> ж ҮзӯҫгҖӮ`,
        );
      }
    };
    checkTemplateFormat(template.sheet_protagonist?.sourceData?.note as string, 'дё»и§’дҝЎжҒҜиЎЁ');
    checkTemplateFormat(template.sheet_important_npc?.sourceData?.note as string, 'йҮҚиҰҒдәәзү©иЎЁ');

    // 8. жӣҝжҚў sheet_protagonist зҡ„ noteпјҲдҪҝз”Ё <еұһжҖ§и§„еҲҷ> ж Үзӯҫпјү
    const protagonistSheet = template.sheet_protagonist;
    if (protagonistSheet?.sourceData?.note) {
      let note = protagonistSheet.sourceData.note as string;
      const originalNote = note;

      note = replaceTag(note, 'еұһжҖ§и§„еҲҷ', attributeRulesContent);

      if (note !== originalNote) {
        protagonistSheet.sourceData.note = note;
        modified = true;
      }
    }

    // 9. жӣҝжҚў sheet_important_npc зҡ„ noteпјҲдҪҝз”Ё <еұһжҖ§и§„еҲҷ> ж Үзӯҫпјү
    const npcSheet = template.sheet_important_npc;
    if (npcSheet?.sourceData?.note) {
      let note = npcSheet.sourceData.note as string;
      const originalNote = note;

      note = replaceTag(note, 'еұһжҖ§и§„еҲҷ', attributeRulesContent);

      if (note !== originalNote) {
        npcSheet.sourceData.note = note;
        modified = true;
      }
    }

    // 10. дҪҝз”Ёж•°жҚ®еә“ API дҝқеӯҳжЁЎжқҝ
    if (modified && typeof dbApi.importTemplateFromData === 'function') {
      dbApi
        .importTemplateFromData(template)
        .then((result: { success: boolean; message: string }) => {
          if (result.success) {
            console.log('[DICE] updateTemplateForActivePreset е·Іжӣҙж–°иЎЁж јжЁЎжқҝпјҢйў„и®ҫ:', presetId);
          } else {
            console.error('[DICE] updateTemplateForActivePreset дҝқеӯҳжЁЎжқҝеӨұиҙҘ:', result.message);
          }
        })
        .catch((err: Error) => {
          console.error('[DICE] updateTemplateForActivePreset дҝқеӯҳжЁЎжқҝеӨұиҙҘ:', err);
        });
    } else if (!modified) {
      console.log('[DICE] updateTemplateForActivePreset ж— йңҖжӣҙж–°пјҲжЁЎжқҝеҶ…е®№жңӘеҸҳеҢ–пјүпјҢйў„и®ҫ:', presetId);
    } else {
      console.warn('[DICE] updateTemplateForActivePreset: importTemplateFromData дёҚеҸҜз”ЁпјҢи·іиҝҮдҝқеӯҳ');
    }
  };

  // ========================================
  // иҮӘе®ҡд№үдәӨдә’и§„еҲҷйў„и®ҫзі»з»ҹ
  // ========================================

  // ActionPresetManager зұ»еһӢе®ҡд№үпјҲд»…з”ЁдәҺж–ҮжЎЈпјҢе®һйҷ…жҳҜ JS еҜ№иұЎпјү
  // interface ActionGroupPreset {
  //   format: 'acu_action_preset_v1';
  //   version: string;
  //   id: string;
  //   name: string;
  //   builtin: boolean;
  //   description?: string;
  //   rules: ActionRule[];
  // }
  // interface ActionRule {
  //   table_keywords: string[];
  //   actions: ActionItem[];
  // }
  // interface ActionItem {
  //   label: string;
  //   icon?: string;
  //   template?: string;
  // }

  // еҶ…зҪ®й»ҳи®ӨдәӨдә’и§„еҲҷйў„и®ҫ
  const BUILTIN_ACTION_PRESETS = [
    {
      format: 'acu_action_preset_v1',
      version: PRESET_FORMAT_VERSION,
      id: '__builtin_default__',
      name: 'й»ҳи®ӨдәӨдә’и§„еҲҷ',
      builtin: true,
      description: 'еҹәдәҺиЎЁж јзұ»еһӢзҡ„й»ҳи®ӨдәӨдә’йҖүйЎ№пјҢеҢ…еҗ«ең°зӮ№гҖҒдәәзү©гҖҒзү©е“ҒгҖҒиЈ…еӨҮгҖҒжҠҖиғҪгҖҒд»»еҠЎгҖҒеҠҝеҠӣзӯүеёёз”Ёи§„еҲҷ',
      rules: [
        {
          table_keywords: ['ең°зӮ№', 'ең°еӣҫ', 'Location', 'Map', 'дё–з•Ң', 'еңәжүҖ'],
          actions: [
            { label: 'еүҚеҫҖ', template: '<user>еүҚеҫҖ{Name}гҖӮ' },
            { label: 'жҺўзҙў', template: '<user>жҺўзҙў{Name}гҖӮ' },
            { label: 'еҒңз•ҷ', template: '<user>еңЁ{Name}еҒңз•ҷгҖӮ' },
          ],
        },
        {
          table_keywords: ['дәәзү©', 'NPC', 'йҮҚиҰҒдәәзү©', 'и§’иүІ', 'еҘідё»'],
          actions: [
            { label: 'дәӨи°Ҳ', template: '<user>дёҺ{Name}дәӨи°ҲгҖӮ' },
            { label: 'и§ӮеҜҹ', template: '<user>и§ӮеҜҹ{Name}гҖӮ' },
            { label: 'жҲҳж–—', template: '<user>дёҺ{Name}жҲҳж–—гҖӮ' },
          ],
        },
        {
          table_keywords: ['зү©е“Ғ', 'иғҢеҢ…', 'йҒ“е…·'],
          actions: [
            { label: 'дҪҝз”Ё', template: '<user>дҪҝз”ЁдәҶ{Name}гҖӮ' },
            { label: 'жҹҘзңӢ', template: '<user>жҹҘзңӢдәҶ{Name}гҖӮ' },
            { label: 'дёўејғ', template: '<user>дёўејғдәҶ{Name}гҖӮ' },
          ],
        },
        {
          table_keywords: ['иЈ…еӨҮ', 'жӯҰеҷЁ', 'йҳІе…·'],
          actions: [
            { label: 'иЈ…еӨҮ', template: '<user>иЈ…еӨҮдәҶ{Name}гҖӮ' },
            { label: 'еҚёдёӢ', template: '<user>еҚёдёӢдәҶ{Name}гҖӮ' },
            { label: 'еҚ–еҮә', template: '<user>еҚ–еҮәдәҶ{Name}гҖӮ' },
          ],
        },
        {
          table_keywords: ['жҠҖиғҪ', 'иғҪеҠӣ'],
          actions: [
            { label: 'дҪҝз”Ё', template: '<user>дҪҝз”Ё{Name}гҖӮ' },
            { label: 'з»ғд№ ', template: '<user>з»ғд№ {Name}гҖӮ' },
          ],
        },
        {
          table_keywords: ['еӨҮеҝҳ', 'д»»еҠЎ', 'дәӢйЎ№'],
          actions: [
            { label: 'иҝҪиёӘ', template: '<user>е°Ҷ{Name}и®ҫдёәеҪ“еүҚиҝҪиёӘзӣ®ж ҮгҖӮ' },
            { label: 'ж•ҙзҗҶ', template: '<user>ж•ҙзҗҶе…ідәҺ{Name}зҡ„дҝЎжҒҜгҖӮ' },
            { label: 'ж”ҫејғ', template: '<user>ж”ҫејғдәҶ{Name}гҖӮ' },
          ],
        },
        {
          table_keywords: ['еҠҝеҠӣ', 'з»„з»Ү', 'йҳөиҗҘ'],
          actions: [
            { label: 'жү“жҺў', template: '<user>жү“жҺў{Name}зҡ„жғ…жҠҘгҖӮ' },
            { label: 'еҠ е…Ҙ', template: '<user>з”іиҜ·еҠ е…Ҙ{Name}гҖӮ' },
            { label: 'еҗҲдҪң', template: '<user>еҗ‘{Name}иҜ·жұӮеҗҲдҪңгҖӮ' },
          ],
        },
      ],
    },
  ];

  const ActionPresetManager = (() => {
    let _cache = null;

    return {
      // иҺ·еҸ–жүҖжңүйў„и®ҫпјҲеҶ…зҪ® + з”ЁжҲ·иҮӘе®ҡд№үпјү
      getAllPresets() {
        if (_cache) return _cache;
        const stored = Store.get(STORAGE_KEY_ACTION_PRESETS, []);
        _cache = [...BUILTIN_ACTION_PRESETS, ...stored];
        return _cache;
      },

      // ж №жҚ®IDиҺ·еҸ–еҚ•дёӘйў„и®ҫ
      getPresetById(id) {
        return this.getAllPresets().find(p => p.id === id) || null;
      },

      // иҺ·еҸ–еҪ“еүҚжҝҖжҙ»зҡ„йў„и®ҫIDпјҲй»ҳи®ӨдёәеҶ…зҪ®йў„и®ҫпјү
      getActivePresetId() {
        const stored = Store.get(STORAGE_KEY_ACTIVE_ACTION_PRESET, '__builtin_default__');
        return stored === null ? '__builtin_default__' : stored;
      },

      // иҺ·еҸ–еҪ“еүҚжҝҖжҙ»зҡ„йў„и®ҫ
      getActivePreset() {
        const activeId = this.getActivePresetId();
        if (!activeId || activeId === '__none__') return null;
        return this.getPresetById(activeId);
      },

      // и®ҫзҪ®жҝҖжҙ»зҡ„йў„и®ҫпјҲ'__none__' иЎЁзӨәе…ЁйғЁе…ій—ӯпјү
      setActivePresetId(id) {
        try {
          const finalId = id === '' || id === undefined || id === null ? '__none__' : id;
          Store.set(STORAGE_KEY_ACTIVE_ACTION_PRESET, finalId);
          _cache = null;
          console.log('[DICE]ActionPresetManager еҲҮжҚўйў„и®ҫ:', finalId);
          return true;
        } catch (err) {
          console.error('[DICE]ActionPresetManager и®ҫзҪ®йў„и®ҫеӨұиҙҘ:', err);
          return false;
        }
      },

      // еҲӣе»әиҮӘе®ҡд№үйў„и®ҫ
      createPreset(preset) {
        const stored = Store.get(STORAGE_KEY_ACTION_PRESETS, []);
        const newPreset = {
          format: 'acu_action_preset_v1',
          version: PRESET_FORMAT_VERSION,
          ...preset,
          id: preset.id || 'custom_' + Date.now(),
          builtin: false,
          createdAt: new Date().toISOString(),
        };
        stored.push(newPreset);
        Store.set(STORAGE_KEY_ACTION_PRESETS, stored);
        _cache = null;
        console.log('[DICE]ActionPresetManager еҲӣе»әйў„и®ҫ:', newPreset.name);
        return newPreset;
      },

      // жӣҙж–°иҮӘе®ҡд№үйў„и®ҫ
      updatePreset(id, updates) {
        const stored = Store.get(STORAGE_KEY_ACTION_PRESETS, []);
        const index = stored.findIndex(p => p.id === id);
        if (index < 0) return false;
        stored[index] = { ...stored[index], ...updates, version: PRESET_FORMAT_VERSION };
        Store.set(STORAGE_KEY_ACTION_PRESETS, stored);
        _cache = null;
        console.log('[DICE]ActionPresetManager жӣҙж–°йў„и®ҫ:', id);
        return true;
      },

      // еҲ йҷӨиҮӘе®ҡд№үйў„и®ҫ
      deletePreset(id) {
        const stored = Store.get(STORAGE_KEY_ACTION_PRESETS, []);
        const filtered = stored.filter(p => p.id !== id);
        if (filtered.length === stored.length) return false;
        Store.set(STORAGE_KEY_ACTION_PRESETS, filtered);
        _cache = null;
        // еҰӮжһңеҲ йҷӨзҡ„жҳҜжҝҖжҙ»йў„и®ҫпјҢжё…йҷӨжҝҖжҙ»зҠ¶жҖҒ
        if (Store.get(STORAGE_KEY_ACTIVE_ACTION_PRESET) === id) {
          Store.set(STORAGE_KEY_ACTIVE_ACTION_PRESET, null);
        }
        console.log('[DICE]ActionPresetManager еҲ йҷӨйў„и®ҫ:', id);
        return true;
      },

      // еҜјеҮәйў„и®ҫдёә JSON
      exportPreset(id) {
        const preset = this.getPresetById(id);
        if (!preset) return null;
        const exported = {
          format: 'acu_action_preset_v1',
          version: PRESET_FORMAT_VERSION,
          ...preset,
        };
        delete exported.builtin;
        delete exported.createdAt;
        return JSON.stringify(exported, null, 2);
      },

      // д»Һ JSON еҜје…Ҙйў„и®ҫ
      importPreset(jsonStr) {
        try {
          const data = JSON.parse(jsonStr);

          // ж ЎйӘҢж јејҸ
          if (data.format !== 'acu_action_preset_v1') {
            throw new Error('дёҚж”ҜжҢҒзҡ„йў„и®ҫж јејҸпјҢйңҖиҰҒ acu_action_preset_v1');
          }

          // еҹәжң¬ж ЎйӘҢ
          if (!data.name || !data.rules || !Array.isArray(data.rules)) {
            throw new Error('йў„и®ҫж•°жҚ®дёҚе®Ңж•ҙпјҢйңҖиҰҒ name е’Ң rules еӯ—ж®ө');
          }

          // з”ҹжҲҗж–°IDйҒҝе…ҚеҶІзӘҒ
          const imported = {
            ...data,
            id: 'imported_' + Date.now(),
            builtin: false,
            version: PRESET_FORMAT_VERSION,
            createdAt: new Date().toISOString(),
          };

          const result = this.createPreset(imported);
          return result;
        } catch (e) {
          console.error('[DICE]ActionPresetManager еҜје…ҘеӨұиҙҘ:', e);
          return null;
        }
      },

      // жё…йҷӨзј“еӯҳ
      clearCache() {
        _cache = null;
      },
    };
  })();

  // ========================================
  // з–ҜзӢӮжЁЎејҸзі»з»ҹ
  // ========================================

  // иҺ·еҸ–з–ҜзӢӮжЁЎејҸй…ҚзҪ®
  const getCrazyModeConfig = () => {
    const stored = Store.get(STORAGE_KEY_CRAZY_MODE, null);
    if (!stored) return { ...DEFAULT_CRAZY_MODE_CONFIG };
    return { ...DEFAULT_CRAZY_MODE_CONFIG, ...stored };
  };

  // дҝқеӯҳз–ҜзӢӮжЁЎејҸй…ҚзҪ®
  const saveCrazyModeConfig = config => {
    Store.set(STORAGE_KEY_CRAZY_MODE, config);
  };

  // еҲӨж–ӯжҳҜеҗҰи§ҰеҸ‘з–ҜзӢӮжЁЎејҸ
  const shouldTriggerCrazyMode = () => {
    const config = getCrazyModeConfig();
    if (!config.enabled) return false;
    // crazyLevel дҪңдёәи§ҰеҸ‘жҰӮзҺҮзҷҫеҲҶжҜ”
    const roll = Math.random() * 100;
    return roll < config.crazyLevel;
  };

  // йҖүжӢ©жҠ•йӘ°зұ»еһӢ
  const selectCrazyRollType = crazyLevel => {
    // crazyLevel < 50: 100% жҷ®йҖҡжЈҖе®ҡ
    // crazyLevel 50-75: 70% жҷ®йҖҡ / 30% еҜ№жҠ—
    // crazyLevel > 75: 50% жҷ®йҖҡ / 50% еҜ№жҠ—
    if (crazyLevel < 50) return 'normal';
    const contestChance = crazyLevel <= 75 ? 0.3 : 0.5;
    return Math.random() < contestChance ? 'contest' : 'normal';
  };

  // ж №жҚ®жқғйҮҚйҡҸжңәйҖүжӢ©
  const weightedRandomSelect = items => {
    if (!items || items.length === 0) return null;
    const totalWeight = items.reduce((sum, item) => sum + (item.weight || 1), 0);
    let random = Math.random() * totalWeight;
    for (const item of items) {
      random -= item.weight || 1;
      if (random <= 0) return item;
    }
    return items[items.length - 1];
  };

  // йҖүжӢ©еҸӮдёҺиҖ…
  const selectCrazyParticipant = () => {
    const config = getCrazyModeConfig();
    const rawData = cachedRawData || getTableData();
    if (!rawData) return null;

    const allTables = processJsonData(rawData || {});
    const playerResult = DashboardDataParser.findTable(allTables, 'player');
    const npcResult = DashboardDataParser.findTable(allTables, 'npc');

    // жһ„е»әеҖҷйҖүеҲ—иЎЁ
    const candidates = [];

    // дё»и§’
    if (playerResult?.data?.rows?.length > 0) {
      const playerName = getDisplayPlayerName() || 'дё»и§’';
      const playerAttrs = getFullAttributesForCharacter('<user>');
      candidates.push({
        name: playerName,
        attrs: playerAttrs,
        isPlayer: true,
        inScene: true,
        weight: config.playerWeight,
      });
    }

    // NPC
    if (npcResult) {
      const npcParsed = DashboardDataParser.parseRows(npcResult, 'npc');
      npcParsed.forEach(npc => {
        if (!npc.name) return;
        const inSceneVal = String(npc.inScene || '').toLowerCase();
        const isInScene = inSceneVal === 'true' || inSceneVal === 'еңЁеңә';
        const npcAttrs = getFullAttributesForCharacter(npc.name);
        candidates.push({
          name: npc.name,
          attrs: npcAttrs,
          isPlayer: false,
          inScene: isInScene,
          weight: isInScene ? config.inSceneNpcWeight : config.offSceneNpcWeight,
        });
      });
    }

    if (candidates.length === 0) return null;
    return weightedRandomSelect(candidates);
  };

  // йҖүжӢ©жЈҖе®ҡеұһжҖ§
  const selectCrazyAttribute = participant => {
    if (!participant) return { name: 'е№ёиҝҗ', value: 50 };

    // 1. дјҳе…ҲдҪҝз”Ёи§’иүІе·ІжңүеұһжҖ§
    if (participant.attrs && participant.attrs.length > 0) {
      const randomAttr = participant.attrs[Math.floor(Math.random() * participant.attrs.length)];
      return { name: randomAttr.name, value: randomAttr.value };
    }

    // 2. дҪҝз”ЁеҪ“еүҚеұһжҖ§и§„еҲҷе®ҡд№үзҡ„еұһжҖ§
    const activePreset = AttributePresetManager.getActivePreset();
    if (activePreset) {
      const allPresetAttrs = [...(activePreset.baseAttributes || []), ...(activePreset.specialAttributes || [])];
      if (allPresetAttrs.length > 0) {
        const randomPresetAttr = allPresetAttrs[Math.floor(Math.random() * allPresetAttrs.length)];
        // дҪҝз”Ё range зҡ„ 50% дҪңдёәй»ҳи®ӨеҖј
        const range = randomPresetAttr.range || [0, 100];
        const defaultValue = Math.floor((range[0] + range[1]) / 2);
        return { name: randomPresetAttr.name, value: defaultValue };
      }
    }

    // 3. дҪҝз”ЁйҡҸжңәжҠҖиғҪжұ 
    const skillPool = getRandomSkillPool();
    if (skillPool && skillPool.length > 0) {
      const randomSkill = skillPool[Math.floor(Math.random() * skillPool.length)];
      return { name: randomSkill, value: 50 };
    }

    return { name: 'е№ёиҝҗ', value: 50 };
  };

  // ж №жҚ®йў„и®ҫжү§иЎҢз–ҜзӢӮжЁЎејҸжҠ•йӘ°
  const crazyRollWithPreset = (preset: AdvancedDicePreset | null, attrValue: number) => {
    if (!preset) {
      // жІЎжңүжҝҖжҙ»йў„и®ҫж—¶пјҢдҪҝз”Ёй»ҳи®Ө d100 и§„еҲҷ
      const roll = Math.floor(Math.random() * 100) + 1;
      let result = 'еӨұиҙҘ';
      if (roll <= 5) result = 'еӨ§жҲҗеҠҹ';
      else if (roll >= 96) result = 'еӨ§еӨұиҙҘ';
      else if (roll <= attrValue) result = 'жҲҗеҠҹ';
      return { roll, result, formula: '1d100' };
    }

    // дҪҝз”Ёйў„и®ҫзҡ„йӘ°еӯҗиЎЁиҫҫејҸ
    const diceExpr = preset.diceExpression || '1d100';
    const rollResult = rollComplexDiceExpression(diceExpr);
    const rollTotal = rollResult.total;

    // ж №жҚ®йў„и®ҫзҡ„ outcomes еҲӨе®ҡз»“жһң
    if (preset.outcomes && preset.outcomes.length > 0) {
      // з®ҖеҢ–зҡ„жқЎд»¶еҲӨж–ӯпјҡж №жҚ®йў„и®ҫзұ»еһӢиҝӣиЎҢеҹәжң¬еҲӨе®ҡ
      const presetId = preset.id;

      if (presetId === 'dnd5e_check') {
        // DND5e: 1d20 + и°ғж•ҙеҖј >= DC
        // и°ғж•ҙеҖј = floor((еұһжҖ§еҖј-10)/2)
        const attrMod = Math.floor((attrValue - 10) / 2);
        const dc = 10; // й»ҳи®ӨDC
        const total = rollTotal + attrMod;

        if (rollResult.rawDice && rollResult.rawDice[0] === 20) {
          return { roll: rollTotal, result: 'еӨ§жҲҗеҠҹ', formula: diceExpr, total, dc, attrMod };
        } else if (rollResult.rawDice && rollResult.rawDice[0] === 1) {
          return { roll: rollTotal, result: 'еӨ§еӨұиҙҘ', formula: diceExpr, total, dc, attrMod };
        } else if (total >= dc) {
          return { roll: rollTotal, result: 'жҲҗеҠҹ', formula: diceExpr, total, dc, attrMod };
        } else {
          return { roll: rollTotal, result: 'еӨұиҙҘ', formula: diceExpr, total, dc, attrMod };
        }
      } else if (presetId === 'coc7_check') {
        // CoC7: 1d100 <= еұһжҖ§еҖј
        if (rollTotal === 1) {
          return { roll: rollTotal, result: 'еӨ§жҲҗеҠҹ', formula: diceExpr };
        } else if ((attrValue < 50 && rollTotal >= 96) || (attrValue >= 50 && rollTotal === 100)) {
          return { roll: rollTotal, result: 'еӨ§еӨұиҙҘ', formula: diceExpr };
        } else if (rollTotal <= Math.floor(attrValue / 5)) {
          return { roll: rollTotal, result: 'жһҒйҡҫжҲҗеҠҹ', formula: diceExpr };
        } else if (rollTotal <= Math.floor(attrValue / 2)) {
          return { roll: rollTotal, result: 'еӣ°йҡҫжҲҗеҠҹ', formula: diceExpr };
        } else if (rollTotal <= attrValue) {
          return { roll: rollTotal, result: 'жҲҗеҠҹ', formula: diceExpr };
        } else {
          return { roll: rollTotal, result: 'еӨұиҙҘ', formula: diceExpr };
        }
      } else if (presetId === 'fate_check') {
        // е‘ҪиҝҗйӘ°: 4dF + еұһжҖ§еҖј
        const total = rollTotal + attrValue;
        const dc = 0; // й»ҳи®ӨDC
        if (total >= dc + 3) {
          return { roll: rollTotal, result: 'еӨ§жҲҗеҠҹ', formula: diceExpr, total };
        } else if (total >= dc) {
          return { roll: rollTotal, result: 'жҲҗеҠҹ', formula: diceExpr, total };
        } else if (total >= dc - 2) {
          return { roll: rollTotal, result: 'еӨұиҙҘ', formula: diceExpr, total };
        } else {
          return { roll: rollTotal, result: 'еӨ§еӨұиҙҘ', formula: diceExpr, total };
        }
      } else if (presetId === 'pbta_check') {
        // PbtA: 2d6 + еұһжҖ§еҖј
        const total = rollTotal + attrValue;
        if (total >= 10) {
          return { roll: rollTotal, result: 'е®Ңе…ЁжҲҗеҠҹ', formula: diceExpr, total };
        } else if (total >= 7) {
          return { roll: rollTotal, result: 'йғЁеҲҶжҲҗеҠҹ', formula: diceExpr, total };
        } else {
          return { roll: rollTotal, result: 'еӨұиҙҘ', formula: diceExpr, total };
        }
      }
    }

    // йҖҡз”ЁеҲӨе®ҡйҖ»иҫ‘пјҡж №жҚ®йӘ°еӯҗзұ»еһӢиҮӘеҠЁйҖүжӢ©жҲҗеҠҹжқЎд»¶
    if (diceExpr.includes('d100') || diceExpr.includes('D100')) {
      // d100 зі»з»ҹ: жҠ•йӘ°з»“жһң <= зӣ®ж ҮеҖј дёәжҲҗеҠҹ
      if (rollTotal <= 5) return { roll: rollTotal, result: 'еӨ§жҲҗеҠҹ', formula: diceExpr };
      if (rollTotal >= 96) return { roll: rollTotal, result: 'еӨ§еӨұиҙҘ', formula: diceExpr };
      if (rollTotal <= attrValue) return { roll: rollTotal, result: 'жҲҗеҠҹ', formula: diceExpr };
      return { roll: rollTotal, result: 'еӨұиҙҘ', formula: diceExpr };
    } else if (diceExpr.includes('d20') || diceExpr.includes('D20')) {
      // d20 зі»з»ҹ: жҠ•йӘ°з»“жһң + дҝ®жӯЈ >= DC дёәжҲҗеҠҹ
      const dc = 10;
      if (rollTotal === 20) return { roll: rollTotal, result: 'еӨ§жҲҗеҠҹ', formula: diceExpr };
      if (rollTotal === 1) return { roll: rollTotal, result: 'еӨ§еӨұиҙҘ', formula: diceExpr };
      if (rollTotal + attrValue >= dc) return { roll: rollTotal, result: 'жҲҗеҠҹ', formula: diceExpr };
      return { roll: rollTotal, result: 'еӨұиҙҘ', formula: diceExpr };
    } else {
      // е…¶д»–йӘ°еӯҗ: з®ҖеҚ•еҲӨж–ӯй«ҳдҪҺ
      const midValue = attrValue;
      if (rollTotal >= midValue) return { roll: rollTotal, result: 'жҲҗеҠҹ', formula: diceExpr };
      return { roll: rollTotal, result: 'еӨұиҙҘ', formula: diceExpr };
    }
  };

  // еҲӨж–ӯжЈҖе®ҡз»“жһң (дҝқз•ҷз”ЁдәҺж— йў„и®ҫж—¶зҡ„е…је®№)
  const judgeCrazyRollResult = (roll, target) => {
    if (roll <= 5) return 'еӨ§жҲҗеҠҹ';
    if (roll >= 96) return 'еӨ§еӨұиҙҘ';
    if (roll <= target) return 'жҲҗеҠҹ';
    return 'еӨұиҙҘ';
  };

  // з”ҹжҲҗз–ҜзӢӮйӘ°еӯҗз»“жһң
  const generateCrazyRoll = () => {
    const config = getCrazyModeConfig();
    const rollType = selectCrazyRollType(config.crazyLevel);

    // иҺ·еҸ–еҪ“еүҚжҝҖжҙ»зҡ„жЈҖе®ҡйў„и®ҫ
    const activePreset = AdvancedDicePresetManager.getActivePreset();

    if (rollType === 'normal') {
      // жҷ®йҖҡжЈҖе®ҡ
      const participant = selectCrazyParticipant();
      if (!participant) return null;

      const attr = selectCrazyAttribute(participant);
      const rollData = crazyRollWithPreset(activePreset, attr.value);

      // ж №жҚ®йў„и®ҫзұ»еһӢж јејҸеҢ–иҫ“еҮә
      if (activePreset) {
        const presetName = activePreset.name;
        if (activePreset.id === 'dnd5e_check' && rollData.attrMod !== undefined) {
          return `<meta:жЈҖе®ҡз»“жһң>\nе…ғеҸҷдәӢпјҡ${participant.name}еҸ‘иө·дәҶгҖҗ${attr.name}гҖ‘жЈҖе®ҡ(${presetName})пјҢ${rollData.formula}=${rollData.roll}пјҢи°ғж•ҙеҖј${rollData.attrMod >= 0 ? '+' : ''}${rollData.attrMod}пјҢжҖ»и®Ў${rollData.total}пјҢDC${rollData.dc}пјҢгҖҗ${rollData.result}гҖ‘\n</meta:жЈҖе®ҡз»“жһң>`;
        } else if (rollData.total !== undefined) {
          return `<meta:жЈҖе®ҡз»“жһң>\nе…ғеҸҷдәӢпјҡ${participant.name}еҸ‘иө·дәҶгҖҗ${attr.name}гҖ‘жЈҖе®ҡ(${presetName})пјҢ${rollData.formula}=${rollData.roll}пјҢжҖ»и®Ў${rollData.total}пјҢгҖҗ${rollData.result}гҖ‘\n</meta:жЈҖе®ҡз»“жһң>`;
        } else {
          return `<meta:жЈҖе®ҡз»“жһң>\nе…ғеҸҷдәӢпјҡ${participant.name}еҸ‘иө·дәҶгҖҗ${attr.name}гҖ‘жЈҖе®ҡ(${presetName})пјҢ${rollData.formula}=${rollData.roll}пјҢзӣ®ж Ү${attr.value}пјҢгҖҗ${rollData.result}гҖ‘\n</meta:жЈҖе®ҡз»“жһң>`;
        }
      }

      // ж— йў„и®ҫж—¶дҪҝз”Ёй»ҳи®Өж јејҸ
      return `<meta:жЈҖе®ҡз»“жһң>\nе…ғеҸҷдәӢпјҡ${participant.name}еҸ‘иө·дәҶгҖҗ${attr.name}гҖ‘жЈҖе®ҡпјҢжҺ·еҮә${rollData.roll}пјҢзӣ®ж Ү${attr.value}пјҢгҖҗ${rollData.result}гҖ‘\n</meta:жЈҖе®ҡз»“жһң>`;
    } else {
      // еҜ№жҠ—жЈҖе®ҡ
      const participant1 = selectCrazyParticipant();
      if (!participant1) return null;

      // йҖүжӢ©з¬¬дәҢдёӘеҸӮдёҺиҖ…пјҲжҺ’йҷӨз¬¬дёҖдёӘпјү
      let participant2 = null;
      for (let i = 0; i < 5; i++) {
        const candidate = selectCrazyParticipant();
        if (candidate && candidate.name !== participant1.name) {
          participant2 = candidate;
          break;
        }
      }

      // еҰӮжһңжүҫдёҚеҲ°з¬¬дәҢдёӘеҸӮдёҺиҖ…пјҢйҷҚзә§дёәжҷ®йҖҡжЈҖе®ҡ
      if (!participant2) {
        const attr = selectCrazyAttribute(participant1);
        const rollData = crazyRollWithPreset(activePreset, attr.value);
        if (activePreset) {
          return `<meta:жЈҖе®ҡз»“жһң>\nе…ғеҸҷдәӢпјҡ${participant1.name}еҸ‘иө·дәҶгҖҗ${attr.name}гҖ‘жЈҖе®ҡ(${activePreset.name})пјҢ${rollData.formula}=${rollData.roll}пјҢзӣ®ж Ү${attr.value}пјҢгҖҗ${rollData.result}гҖ‘\n</meta:жЈҖе®ҡз»“жһң>`;
        }
        return `<meta:жЈҖе®ҡз»“жһң>\nе…ғеҸҷдәӢпјҡ${participant1.name}еҸ‘иө·дәҶгҖҗ${attr.name}гҖ‘жЈҖе®ҡпјҢжҺ·еҮә${rollData.roll}пјҢзӣ®ж Ү${attr.value}пјҢгҖҗ${rollData.result}гҖ‘\n</meta:жЈҖе®ҡз»“жһң>`;
      }

      const attr1 = selectCrazyAttribute(participant1);
      const attr2 = selectCrazyAttribute(participant2);
      const rollData1 = crazyRollWithPreset(activePreset, attr1.value);
      const rollData2 = crazyRollWithPreset(activePreset, attr2.value);

      // и®Ўз®—жҲҗеҠҹеәҰе’ҢеҲӨе®ҡз»“жһң
      const result1 = rollData1.result;
      const result2 = rollData2.result;

      // ж №жҚ®йў„и®ҫзұ»еһӢи®Ўз®—иғңиҙҹ
      let winner;
      if (
        activePreset &&
        (activePreset.id === 'dnd5e_check' || activePreset.id === 'pbta_check' || activePreset.id === 'fate_check')
      ) {
        // еҠ еҖјзі»з»ҹ: жҜ”иҫғжҖ»еҖј
        const total1 = rollData1.total !== undefined ? rollData1.total : rollData1.roll + attr1.value;
        const total2 = rollData2.total !== undefined ? rollData2.total : rollData2.roll + attr2.value;
        if (total1 > total2) {
          winner = `${participant1.name}иғңеҮә`;
        } else if (total2 > total1) {
          winner = `${participant2.name}иғңеҮә`;
        } else {
          winner = 'е№іеұҖ';
        }
      } else {
        // d100зі»з»ҹ: жҜ”иҫғжҲҗеҠҹдҪҷйҮҸ (зӣ®ж ҮеҖј - жҠ•йӘ°з»“жһң)
        const margin1 = attr1.value - rollData1.roll;
        const margin2 = attr2.value - rollData2.roll;
        if (margin1 > margin2) {
          winner = `${participant1.name}иғңеҮә`;
        } else if (margin2 > margin1) {
          winner = `${participant2.name}иғңеҮә`;
        } else {
          winner = 'е№іеұҖ';
        }
      }

      // ж јејҸдёҺзҺ°жңүеҜ№жҠ—жЈҖе®ҡдҝқжҢҒдёҖиҮҙ
      const presetLabel = activePreset ? `(${activePreset.name})` : '';
      return (
        `<meta:жЈҖе®ҡз»“жһң>\n` +
        `е…ғеҸҷдәӢпјҡиҝӣиЎҢдәҶдёҖж¬ЎгҖҗ${participant1.name} ${attr1.name} vs ${participant2.name} ${attr2.name}гҖ‘зҡ„еҜ№жҠ—жЈҖе®ҡ${presetLabel}гҖӮ` +
        `${participant1.name} ${attr1.name} (зӣ®ж Ү${attr1.value}) ${rollData1.formula}=${rollData1.roll}пјҢеҲӨе®ҡдёәгҖҗ${result1}гҖ‘пјӣ` +
        `${participant2.name} ${attr2.name} (зӣ®ж Ү${attr2.value}) ${rollData2.formula}=${rollData2.roll}пјҢеҲӨе®ҡдёәгҖҗ${result2}гҖ‘гҖӮ` +
        `жңҖз»Ҳз»“жһңпјҡгҖҗ${winner}гҖ‘\n` +
        `</meta:жЈҖе®ҡз»“жһң>`
      );
    }
  };

  // ========================================
  // е…¬ејҸи§ЈжһҗеҷЁзі»з»ҹпјҲж”ҜжҢҒйӘ°еӯҗиЎЁиҫҫејҸе’ҢеҸҳйҮҸеј•з”Ёпјү
  // ========================================

  /**
   * жҠ•еҚ•дёӘйӘ°еӯҗиЎЁиҫҫејҸ
   * ж”ҜжҢҒ: 3d6, 4d6kh3, 4d6dl1, 4d6dh1
   * @returns ж ҮеҮҶеҢ– RollResultпјҢи§ЈжһҗеӨұиҙҘ total дёә NaN
   */
  const rollDiceExpression = (expr: string): RollResult => {
    const formula = String(expr);
    const rollDice = (sides: number) => Math.floor(Math.random() * sides) + 1;

    // еҢ№й…Қ XdY жҲ– XdF иҜӯжі•пјҢж”ҜжҢҒйҮҚжҺ·гҖҒзҲҶзӮёгҖҒдҝқз•ҷ/иҲҚејғе’ҢжҲҗеҠҹи®Ўж•°
    const match = formula.match(
      /^(\d*)d(\d+|F)([bp]\d+)?(r[o]?(?:[><!=]+)?\d*)?(!!?(?:[><!=]+\d+)?)?(kh\d+|kl\d+|dh\d+|dl\d+)?((?:[><!=]+)\d+)?$/i,
    );
    if (!match) {
      return {
        total: Number.NaN,
        rawDice: [],
        keptDice: [],
        formula,
        breakdown: formula ? `${formula}=NaN` : 'NaN',
        tags: [],
      };
    }

    const [, countStr, sidesOrF, cocPart, rerollPart, explodePart, keepDrop, successPart] = match;
    const count = countStr ? parseInt(countStr, 10) : 1;
    const isFate = sidesOrF.toUpperCase() === 'F';
    const sides = isFate ? 0 : parseInt(sidesOrF, 10);

    let rolls: number[] = [];
    if (isFate) {
      // FATE йӘ°еӯҗ: еҸ–еҖј [-1, 0, 1]
      rolls = Array.from({ length: count }, () => Math.floor(Math.random() * 3) - 1);
    } else {
      // жҷ®йҖҡйӘ°еӯҗ

      // и§ЈжһҗйҮҚжҺ·дҝ®йҘ°з¬Ұ
      let rerollType = null;
      let rerollCompare = '=';
      let rerollValue = 1;

      if (rerollPart) {
        const m = rerollPart.match(/^(r[o]?)([><!=]+)?(\d+)?$/i);
        if (m) {
          rerollType = m[1].toLowerCase();
          if (m[2]) rerollCompare = m[2];
          if (m[3]) rerollValue = parseInt(m[3], 10);
          else if (!m[2]) rerollValue = 1; // д»… r жҲ– ro й»ҳи®Өдёә 1
        }
      }

      const checkReroll = (val: number) => {
        if (!rerollType) return false;
        switch (rerollCompare) {
          case '>=':
            return val >= rerollValue;
          case '<=':
            return val <= rerollValue;
          case '=':
          case '==':
            return val === rerollValue;
          case '>':
            return val > rerollValue;
          case '<':
            return val < rerollValue;
          case '!=':
          case '<>':
            return val !== rerollValue;
          default:
            return val === rerollValue;
        }
      };

      // и§ЈжһҗзҲҶзӮёдҝ®йҘ°з¬Ұ
      let explodeType = null;
      let explodeCompare = '=';
      let explodeValue = sides;

      if (explodePart) {
        const m = explodePart.match(/^(!!?)([><=!]+)?(\d+)?$/);
        if (m) {
          explodeType = m[1];
          if (m[2]) explodeCompare = m[2];
          if (m[3]) explodeValue = parseInt(m[3], 10);
        }
      }

      const checkExplode = (val: number) => {
        if (!explodeType) return false;
        switch (explodeCompare) {
          case '>=':
            return val >= explodeValue;
          case '<=':
            return val <= explodeValue;
          case '=':
          case '==':
            return val === explodeValue;
          case '>':
            return val > explodeValue;
          case '<':
            return val < explodeValue;
          case '!=':
          case '<>':
            return val !== explodeValue;
          default:
            return val === sides;
        }
      };

      // и§Јжһҗ CoC еҘ–еҠұ/жғ©зҪҡйӘ° (д»…еҜ№ d100 з”ҹж•Ҳ)
      let cocType = null;
      let cocCount = 0;
      if (cocPart && sides === 100) {
        const m = cocPart.match(/^([bp])(\d+)$/i);
        if (m) {
          cocType = m[1].toLowerCase();
          cocCount = parseInt(m[2], 10);
        }
      }

      for (let i = 0; i < count; i++) {
        let val = rollDice(sides);

        // CoC еҘ–еҠұ/жғ©зҪҡйӘ°йҖ»иҫ‘
        if (cocType) {
          const tens = Math.floor((val === 100 ? 0 : val) / 10);
          const units = val % 10;
          const additionalTens = Array.from({ length: cocCount }, () => Math.floor(Math.random() * 10));
          const allTens = [tens, ...additionalTens];
          let finalTens;
          if (cocType === 'b') {
            finalTens = Math.min(...allTens);
          } else {
            finalTens = Math.max(...allTens);
          }
          const result = finalTens * 10 + units;
          val = result === 0 ? 100 : result;
        }

        // йҮҚжҺ·йҖ»иҫ‘ (еңЁзҲҶзӮёд№ӢеүҚжү§иЎҢ)
        if (rerollType) {
          let rerollCount = 0;
          while (checkReroll(val) && rerollCount < 100) {
            rerollCount++;
            val = rollDice(sides);
            if (rerollType === 'ro') break; // ro еҸӘйҮҚжҺ·дёҖж¬Ў
          }
        }

        if (explodeType) {
          let currentVal = val;
          let nextToCheck = val;
          let explodeCount = 0;
          while (checkExplode(nextToCheck) && explodeCount < 100) {
            explodeCount++;
            nextToCheck = rollDice(sides);
            if (explodeType === '!') {
              rolls.push(currentVal);
              currentVal = nextToCheck;
            } else {
              currentVal += nextToCheck;
            }
          }
          rolls.push(currentVal);
        } else {
          rolls.push(val);
        }
      }
    }

    const rawDice = [...rolls];
    let keptDice = [...rolls];

    // еӨ„зҗҶ keep/drop
    if (keepDrop) {
      const kd = keepDrop.toLowerCase();
      const n = parseInt(kd.slice(2), 10);
      const sorted = [...keptDice].sort((a, b) => b - a); // йҷҚеәҸжҺ’еҲ—

      if (kd.startsWith('kh'))
        keptDice = sorted.slice(0, n); // дҝқз•ҷжңҖй«ҳnдёӘ
      else if (kd.startsWith('kl'))
        keptDice = sorted.slice(-n); // дҝқз•ҷжңҖдҪҺnдёӘ
      else if (kd.startsWith('dh'))
        keptDice = sorted.slice(n); // еҺ»жҺүжңҖй«ҳnдёӘ
      else if (kd.startsWith('dl')) keptDice = sorted.slice(0, -n); // еҺ»жҺүжңҖдҪҺnдёӘ
    }

    let total = keptDice.reduce((a, b) => a + b, 0);

    // еӨ„зҗҶжҲҗеҠҹи®Ўж•° (йӘ°жұ )
    if (successPart) {
      const sm = successPart.match(/^([><!=]+)(\d+)$/);
      if (sm) {
        const op = sm[1];
        const val = parseInt(sm[2], 10);
        const isSuccess = (roll: number) => {
          switch (op) {
            case '>=':
              return roll >= val;
            case '<=':
              return roll <= val;
            case '=':
            case '==':
              return roll === val;
            case '>':
              return roll > val;
            case '<':
              return roll < val;
            case '!=':
            case '<>':
              return roll !== val;
            default:
              return false;
          }
        };
        total = keptDice.filter(isSuccess).length;
      }
    }

    const tags: string[] = [];
    if (!isFate && sides === 20) {
      const diceToCheck = keptDice.length > 0 ? keptDice : rawDice;
      if (diceToCheck.some(roll => roll === 20)) tags.push('nat20');
      if (diceToCheck.some(roll => roll === 1)) tags.push('nat1');
    }

    const totalText = Number.isNaN(total) ? 'NaN' : String(total);
    const diceList = rawDice.length > 0 ? `[${rawDice.join(',')}]` : '[]';
    const showList = rawDice.length !== 1 || Boolean(keepDrop) || Boolean(successPart);
    const breakdown = showList ? `${formula}=${diceList}вҶ’${totalText}` : `${formula}=${totalText}`;

    return {
      total,
      rawDice,
      keptDice,
      formula,
      breakdown,
      tags,
    };
  };

  // и®Ўз®—йӘ°еӯҗиЎЁиҫҫејҸзҡ„жңҹжңӣеҖјпјҲз”ЁдәҺй»ҳи®Өзӣ®ж ҮеҖјпјү
  const calculateDiceExpectedValue = (diceExpr: string): number => {
    const formula = String(diceExpr).replace(/\s+/g, '');
    if (!formula) return Number.NaN;

    const parts = formula.match(/[+-]?[^+-]+/g);
    if (!parts) return Number.NaN;

    let total = 0;
    for (const part of parts) {
      if (!part) continue;
      const sign = part.startsWith('-') ? -1 : 1;
      const body = part.replace(/^[+-]/, '');
      if (!body) continue;

      const diceMatch = body.match(
        /^(\d*)d(\d+|F)([bp]\d+)?(r[o]?(?:[><!=]+)?\d*)?(!!?(?:[><!=]+\d+)?)?(kh\d+|kl\d+|dh\d+|dl\d+)?((?:[><!=]+)\d+)?$/i,
      );

      if (diceMatch) {
        const [, countStr, sidesOrF, , , , keepDrop] = diceMatch;
        const count = countStr ? parseInt(countStr, 10) : 1;
        const isFate = sidesOrF.toUpperCase() === 'F';
        const sides = isFate ? 0 : parseInt(sidesOrF, 10);
        const expectedPerDie = isFate ? 0 : (1 + sides) / 2;

        let keptCount = count;
        if (keepDrop) {
          const keepDropType = keepDrop.slice(0, 2);
          const keepDropValue = parseInt(keepDrop.slice(2), 10);
          if (!Number.isNaN(keepDropValue)) {
            if (keepDropType === 'kh' || keepDropType === 'kl') {
              keptCount = Math.min(count, keepDropValue);
            } else if (keepDropType === 'dh' || keepDropType === 'dl') {
              keptCount = Math.max(0, count - keepDropValue);
            }
          }
        }

        total += sign * keptCount * expectedPerDie;
        continue;
      }

      const numericValue = Number(body);
      if (Number.isNaN(numericValue)) {
        return Number.NaN;
      }
      total += sign * numericValue;
    }

    return total;
  };

  // еӨҚеҗҲйӘ°еӯҗиЎЁиҫҫејҸжҺ·йӘ°пјҲж”ҜжҢҒ 2d6+33 зӯүз®—жңҜдҝ®йҘ°з¬Ұпјү
  const rollComplexDiceExpression = (expr: string): RollResult => {
    const formula = String(expr).replace(/\s+/g, '');
    if (!formula) {
      return { total: Number.NaN, rawDice: [], keptDice: [], formula: '', breakdown: 'NaN', tags: [] };
    }

    // е…Ҳе°қиҜ•з®ҖеҚ•иЎЁиҫҫејҸ
    const simpleResult = rollDiceExpression(formula);
    if (!Number.isNaN(simpleResult.total)) {
      return simpleResult;
    }

    // и§ЈжһҗеӨҚеҗҲиЎЁиҫҫејҸпјҲеҰӮ 2d6+33, d20-5пјү
    const parts = formula.match(/[+-]?[^+-]+/g);
    if (!parts) {
      return { total: Number.NaN, rawDice: [], keptDice: [], formula, breakdown: `${formula}=NaN`, tags: [] };
    }

    let total = 0;
    const allRawDice: number[] = [];
    const allKeptDice: number[] = [];
    const breakdownParts: string[] = [];
    const allTags: string[] = [];

    for (const part of parts) {
      if (!part) continue;
      const sign = part.startsWith('-') ? -1 : 1;
      const body = part.replace(/^[+-]/, '');
      if (!body) continue;

      // е°қиҜ•дҪңдёәйӘ°еӯҗиЎЁиҫҫејҸи§Јжһҗ
      const diceResult = rollDiceExpression(body);
      if (!Number.isNaN(diceResult.total)) {
        total += sign * diceResult.total;
        allRawDice.push(...diceResult.rawDice);
        allKeptDice.push(...diceResult.keptDice);
        breakdownParts.push(
          sign === -1
            ? `-${diceResult.breakdown}`
            : breakdownParts.length > 0
              ? `+${diceResult.breakdown}`
              : diceResult.breakdown,
        );
        allTags.push(...diceResult.tags);
        continue;
      }

      // е°қиҜ•дҪңдёәж•°еӯ—и§Јжһҗ
      const numericValue = Number(body);
      if (!Number.isNaN(numericValue)) {
        total += sign * numericValue;
        const signedValue = sign * numericValue;
        breakdownParts.push(signedValue >= 0 && breakdownParts.length > 0 ? `+${signedValue}` : String(signedValue));
        continue;
      }

      // ж— жі•и§Јжһҗ
      return { total: Number.NaN, rawDice: [], keptDice: [], formula, breakdown: `${formula}=NaN`, tags: [] };
    }

    return {
      total,
      rawDice: allRawDice,
      keptDice: allKeptDice,
      formula,
      breakdown: `${breakdownParts.join('')}=${total}`,
      tags: allTags,
    };
  };

  /**
   * и§Јжһҗе№¶и®Ўз®—е…¬ејҸпјҲж”ҜжҢҒеҸҳйҮҸеј•з”Ёпјү
   * @param formula е…¬ејҸеӯ—з¬ҰдёІпјҢеҰӮ "еҠӣйҮҸ/2+1d10" жҲ– "3d6*5"
   * @param context еҸҳйҮҸдёҠдёӢж–ҮпјҢеҰӮ { еҠӣйҮҸ: 50, ж•ҸжҚ·: 40 }
   * @returns и®Ўз®—з»“жһңпјҲж•ҙж•°пјү
   */
  const evaluateFormula = (formula, context = {}) => {
    if (!formula) return 0;

    let expr = String(formula).trim();

    // 1. жӣҝжҚўеҸҳйҮҸдёәж•°еҖјпјҲжҢүй•ҝеәҰйҷҚеәҸжӣҝжҚўпјҢйҒҝе…ҚйғЁеҲҶеҢ№й…Қпјү
    const varNames = Object.keys(context).sort((a, b) => b.length - a.length);
    for (const name of varNames) {
      const value = context[name];
      if (typeof value === 'number' && !isNaN(value)) {
        // з”ЁжӢ¬еҸ·еҢ…иЈ№йҒҝе…Қиҝҗз®—дјҳе…Ҳзә§й—®йўҳ
        expr = expr.split(name).join(`(${value})`);
      }
    }

    // 2. жӣҝжҚўйӘ°еӯҗиЎЁиҫҫејҸдёәж•°еҖј
    expr = expr.replace(
      /\d*d(?:\d+|F)(?:[bp]\d+)?(?:r[o]?(?:[><!=]+)?\d*)?(?:!!?(?:[><!=]+\d+)?)?(?:kh\d+|kl\d+|dh\d+|dl\d+)?(?:(?:[><!=]+)\d+)?/gi,
      match => {
        const result = rollDiceExpression(match);
        return Number.isNaN(result.total) ? '0' : String(result.total);
      },
    );

    // 3. е®үе…ЁжҖ§жЈҖжҹҘпјҡеҸӘе…Ғи®ёж•°еӯ—е’Ңеҹәжң¬иҝҗз®—з¬Ұ
    if (!/^[\d\s+\-*/().]+$/.test(expr)) {
      console.warn('[DICE]evaluateFormula е…¬ејҸеҢ…еҗ«йқһжі•еӯ—з¬Ұ:', formula, 'вҶ’', expr);
      return 0;
    }

    // 4. и®Ўз®—ж•°еӯҰиЎЁиҫҫејҸ
    try {
      // eslint-disable-next-line no-new-func
      const result = new Function(`return (${expr})`)();
      return Math.round(result); // еӣӣиҲҚдә”е…Ҙдёәж•ҙж•°
    } catch (e) {
      console.error('[DICE]evaluateFormula е…¬ејҸи®Ўз®—еӨұиҙҘ:', formula, 'вҶ’', expr, e);
      return 0;
    }
  };

  /**
   * иҜ„дј°жқЎд»¶иЎЁиҫҫејҸпјҲж”ҜжҢҒжҜ”иҫғиҝҗз®—е’ҢйҖ»иҫ‘иҝҗз®—пјү
   * @param {string} formula иЎЁиҫҫејҸеӯ—з¬ҰдёІ
   * @param {Record<string, number>} context еҸҳйҮҸдёҠдёӢж–Ү
   * @returns {{success: boolean, value?: number | boolean, error?: string}}
   */
  const evaluateCondition = (formula, context = {}) => {
    if (!formula || typeof formula !== 'string') return { success: true, value: 0 };

    const functionHandlers: Record<string, { minArgs: number; maxArgs: number; apply: (args: number[]) => number }> = {
      abs: { minArgs: 1, maxArgs: 1, apply: args => Math.abs(args[0]) },
      floor: { minArgs: 1, maxArgs: 1, apply: args => Math.floor(args[0]) },
      min: { minArgs: 2, maxArgs: Number.POSITIVE_INFINITY, apply: args => Math.min(...args) },
      max: { minArgs: 2, maxArgs: Number.POSITIVE_INFINITY, apply: args => Math.max(...args) },
    };

    // ж”ҜжҢҒ $roll.hasTag("tag")
    if (context && context.$roll && typeof context.$roll === 'object') {
      const roll = context.$roll as RollResult;
      functionHandlers['$roll.hastag'] = {
        minArgs: 1,
        maxArgs: 1,
        apply: (args: any[]) => {
          const tag = String(args[0]);
          return (roll.tags ?? []).includes(tag) ? 1 : 0;
        },
      };
    }

    function evaluateExpression(expression: string): { success: boolean; value?: number | boolean; error?: string } {
      // 2. е®үе…ЁжЈҖжҹҘ
      // жЈҖжҹҘжҳҜеҗҰеҢ…еҗ«йқһжі•еӯ—з¬Ұ
      const illegal = expression.match(/[^0-9+\-*/()><=!&| .]/g);
      if (illegal) {
        return { success: false, error: `еҢ…еҗ«йқһжі•еӯ—з¬Ұ: ${illegal.join('')}` };
      }

      // 3. еҲҶиҜҚ (Tokenization)
      // йңҖиҰҒеӨ„зҗҶеӨҡеӯ—з¬Ұиҝҗз®—з¬Ұ: >=, <=, ==, !=, &&, ||
      const tokens = [];
      let i = 0;
      while (i < expression.length) {
        const char = expression[i];
        if (/\s/.test(char)) {
          i++;
          continue;
        }
        if (/\d/.test(char)) {
          let num = '';
          while (i < expression.length && /[\d.]/.test(expression[i])) {
            num += expression[i++];
          }
          tokens.push({ type: 'NUMBER', value: parseFloat(num) });
          continue;
        }

        // еӨ„зҗҶдёүеӯ—з¬Ұж“ҚдҪңз¬Ұ (===, !==)
        const threeChar = expression.substring(i, i + 3);
        if (['===', '!=='].includes(threeChar)) {
          tokens.push({ type: 'OPERATOR', value: threeChar });
          i += 3;
          continue;
        }

        // еӨ„зҗҶеҸҢеӯ—з¬Ұж“ҚдҪңз¬Ұ
        const twoChar = expression.substring(i, i + 2);
        if (['>=', '<=', '==', '!=', '&&', '||'].includes(twoChar)) {
          tokens.push({ type: 'OPERATOR', value: twoChar });
          i += 2;
          continue;
        }

        // еӨ„зҗҶеҚ•еӯ—з¬Ұж“ҚдҪңз¬Ұ
        if (['+', '-', '*', '/', '%', '>', '<', '(', ')'].includes(char)) {
          // еӨ„зҗҶдёҖе…ғиҙҹеҸ·пјҡеҰӮжһң '-' еҮәзҺ°еңЁејҖеӨҙжҲ–зҙ§и·ҹеңЁж“ҚдҪңз¬Ұ/е·ҰжӢ¬еҸ·еҗҺйқўпјҢеҲҷжҳҜиҙҹеҸ·
          if (char === '-' || char === '+') {
            const lastToken = tokens[tokens.length - 1];
            const isUnary = !lastToken || lastToken.type === 'OPERATOR' || lastToken.value === '(';
            if (isUnary) {
              // иҜ»еҸ–еҗҺйқўзҡ„ж•°еӯ—
              let num = char;
              i++;
              while (i < expression.length && /[\d.]/.test(expression[i])) {
                num += expression[i++];
              }
              if (num.length > 1) {
                tokens.push({ type: 'NUMBER', value: parseFloat(num) });
                continue;
              }
              // еҰӮжһңеҸӘжңү '-' жІЎжңүж•°еӯ—пјҢеӣһйҖҖе№¶дҪңдёәж“ҚдҪңз¬ҰеӨ„зҗҶ
              i--;
            }
          }
          if (char === '>' || char === '<') {
            const nextChar = expression[i + 1];
            if (nextChar === char) {
              // еӨ„зҗҶ >> жҲ– <<
              return { success: false, error: `иҜӯжі•й”ҷиҜҜ: ж— жі•и§Јжһҗж“ҚдҪңз¬Ұ "${char}${char}"` };
            }
          }
          tokens.push({ type: 'OPERATOR', value: char });
          i++;
          continue;
        }

        // жҚ•иҺ·жңӘеӨ„зҗҶзҡ„еӯ—з¬Ұ
        if (['=', '!', '&', '|'].includes(char)) {
          return { success: false, error: `иҜӯжі•й”ҷиҜҜ: еӯӨз«Ӣзҡ„ж“ҚдҪңз¬Ұ "${char}"` };
        }
        return { success: false, error: `иҜӯжі•й”ҷиҜҜ: ж— жі•и§ЈжһҗжҲ–еӯӨз«Ӣзҡ„еӯ—з¬Ұ "${char}"` };
      }

      // 4. Shunting-yard з®—жі•
      const ops = {
        '||': { prec: 1, assoc: 'L' },
        '&&': { prec: 2, assoc: 'L' },
        '==': { prec: 3, assoc: 'L' },
        '!=': { prec: 3, assoc: 'L' },
        '===': { prec: 3, assoc: 'L' },
        '!==': { prec: 3, assoc: 'L' },
        '>': { prec: 4, assoc: 'L' },
        '<': { prec: 4, assoc: 'L' },
        '>=': { prec: 4, assoc: 'L' },
        '<=': { prec: 4, assoc: 'L' },
        '+': { prec: 5, assoc: 'L' },
        '-': { prec: 5, assoc: 'L' },
        '*': { prec: 6, assoc: 'L' },
        '/': { prec: 6, assoc: 'L' },
        '%': { prec: 6, assoc: 'L' },
      };

      const outputQueue = [];
      const operatorStack = [];

      for (const token of tokens) {
        if (token.type === 'NUMBER') {
          outputQueue.push(token);
        } else if (token.value === '(') {
          operatorStack.push(token);
        } else if (token.value === ')') {
          while (operatorStack.length > 0 && operatorStack[operatorStack.length - 1].value !== '(') {
            outputQueue.push(operatorStack.pop());
          }
          if (operatorStack.length === 0) return { success: false, error: 'жӢ¬еҸ·дёҚеҢ№й…Қ' };
          operatorStack.pop(); // еј№еҮә '('
        } else {
          const o1 = token.value;
          while (operatorStack.length > 0) {
            const o2 = operatorStack[operatorStack.length - 1].value;
            if (o2 === '(') break;
            if (ops[o2].prec > ops[o1].prec || (ops[o2].prec === ops[o1].prec && ops[o1].assoc === 'L')) {
              outputQueue.push(operatorStack.pop());
            } else {
              break;
            }
          }
          operatorStack.push(token);
        }
      }

      while (operatorStack.length > 0) {
        const op = operatorStack.pop();
        if (op.value === '(') return { success: false, error: 'жӢ¬еҸ·дёҚеҢ№й…Қ' };
        outputQueue.push(op);
      }

      // 5. ж ҲжұӮеҖј
      const evalStack = [];
      for (const token of outputQueue) {
        if (token.type === 'NUMBER') {
          evalStack.push(token.value);
        } else {
          const b = evalStack.pop();
          const a = evalStack.pop();
          let res;
          switch (token.value) {
            case '+':
              res = a + b;
              break;
            case '-':
              res = a - b;
              break;
            case '*':
              res = a * b;
              break;
            case '/':
              res = a / b;
              break;
            case '%':
              res = a % b;
              break;
            case '>':
              res = a > b;
              break;
            case '<':
              res = a < b;
              break;
            case '>=':
              res = a >= b;
              break;
            case '<=':
              res = a <= b;
              break;
            case '==':
              res = a == b;
              break;
            case '!=':
              res = a != b;
              break;
            case '===':
              res = a === b;
              break;
            case '!==':
              res = a !== b;
              break;
            case '&&':
              res = a && b ? 1 : 0;
              break;
            case '||':
              res = a || b ? 1 : 0;
              break;
            default:
              return { success: false, error: `жңӘзҹҘж“ҚдҪңз¬Ұ: ${token.value}` };
          }
          evalStack.push(res);
        }
      }

      if (evalStack.length !== 1) return { success: false, error: 'ж— ж•Ҳзҡ„иЎЁиҫҫејҸ' };
      return { success: true, value: evalStack[0] };
    }

    function normalizeNumberLiteral(value: number): string {
      const text = String(value);
      if (value < 0) return `(0${text})`;
      return `(${text})`;
    }

    function splitArguments(argsText: string): string[] {
      const args: string[] = [];
      let depth = 0;
      let start = 0;
      let inQuote = false;
      for (let index = 0; index < argsText.length; index++) {
        const char = argsText[index];
        if (char === '"' || char === "'") {
          inQuote = !inQuote;
        }
        if (inQuote) continue;

        if (char === '(') {
          depth++;
        } else if (char === ')') {
          depth--;
        } else if (char === ',' && depth === 0) {
          args.push(argsText.slice(start, index).trim());
          start = index + 1;
        }
      }
      args.push(argsText.slice(start).trim());
      return args;
    }

    function findMatchingParen(source: string, startIndex: number): number {
      let depth = 0;
      for (let index = startIndex; index < source.length; index++) {
        const char = source[index];
        if (char === '(') depth++;
        if (char === ')') {
          depth--;
          if (depth === 0) return index;
        }
      }
      return -1;
    }

    function evaluateArgumentValue(argExpr: string): { success: boolean; value?: any; error?: string } {
      const trimmed = argExpr.trim();
      if (!trimmed) return { success: false, error: 'еҮҪж•°еҸӮж•°дёҚиғҪдёәз©ә' };

      // еӨ„зҗҶеӯ—з¬ҰдёІеӯ—йқўйҮҸ
      if ((trimmed.startsWith('"') && trimmed.endsWith('"')) || trimmed.startsWith("'")) {
        return { success: true, value: trimmed.slice(1, -1) };
      }

      // [дҝ®еӨҚ] е…ҲжӣҝжҚўеҸҳйҮҸпјҢеҶҚеӨ„зҗҶеҮҪж•°
      let exprWithVars = trimmed;
      const varPattern = /\$[a-zA-Z_]\w*/g;
      exprWithVars = exprWithVars.replace(varPattern, match => {
        const val = context[match];
        return typeof val === 'number' && !isNaN(val) ? String(val) : '0';
      });

      const resolved = resolveFunctions(exprWithVars);
      if (!resolved.success || resolved.expr === undefined) {
        return { success: false, error: resolved.error ?? 'еҮҪж•°еҸӮж•°и§ЈжһҗеӨұиҙҘ' };
      }

      const dicePattern = /\d*d(?:\d+|F)/i;
      if (dicePattern.test(resolved.expr)) {
        const formulaValue = evaluateFormula(resolved.expr, context);
        if (typeof formulaValue === 'number' && Number.isFinite(formulaValue)) {
          return { success: true, value: formulaValue };
        }
      }

      const evalResult = evaluateExpression(resolved.expr);
      if (!evalResult.success || evalResult.value === undefined) {
        return { success: false, error: evalResult.error ?? 'еҮҪж•°еҸӮж•°и®Ўз®—еӨұиҙҘ' };
      }
      const value = typeof evalResult.value === 'boolean' ? (evalResult.value ? 1 : 0) : evalResult.value;
      if (typeof value !== 'number' || Number.isNaN(value)) {
        return { success: false, error: 'еҮҪж•°еҸӮж•°дёҚжҳҜжңүж•Ҳж•°еӯ—' };
      }
      return { success: true, value };
    }

    function resolveFunctions(source: string): { success: boolean; expr?: string; error?: string } {
      let result = '';
      let index = 0;
      const isIdentifierStart = (char: string): boolean => /[a-zA-Z_]/.test(char);
      const isIdentifierChar = (char: string): boolean => /[a-zA-Z0-9_]/.test(char);

      while (index < source.length) {
        const char = source[index];
        if (isIdentifierStart(char)) {
          let name = char;
          index++;
          while (index < source.length && (isIdentifierChar(source[index]) || source[index] === '.')) {
            name += source[index];
            index++;
          }

          // еӨ„зҗҶ true/false еёғе°”еӯ—йқўйҮҸ
          const nameLower = name.toLowerCase();
          if (nameLower === 'true') {
            result += '1';
            continue;
          }
          if (nameLower === 'false') {
            result += '0';
            continue;
          }

          let nextIndex = index;
          while (nextIndex < source.length && /\s/.test(source[nextIndex])) {
            nextIndex++;
          }

          if (source[nextIndex] !== '(') {
            return { success: false, error: `жңӘзҹҘеҮҪж•°жҲ–ж ҮиҜҶз¬Ұ: ${name}` };
          }

          const closeIndex = findMatchingParen(source, nextIndex);
          if (closeIndex === -1) return { success: false, error: 'жӢ¬еҸ·дёҚеҢ№й…Қ' };

          const argsText = source.slice(nextIndex + 1, closeIndex);
          const args = splitArguments(argsText);
          const key = name.toLowerCase();
          const handler = functionHandlers[key];
          if (!handler) return { success: false, error: `дёҚж”ҜжҢҒзҡ„еҮҪж•°: ${name}` };
          if (args.length < handler.minArgs || args.length > handler.maxArgs) {
            return { success: false, error: `еҮҪж•° ${name} еҸӮж•°ж•°йҮҸдёҚеҗҲжі•` };
          }

          const values: number[] = [];
          for (const arg of args) {
            if (!arg) return { success: false, error: `еҮҪж•° ${name} еҸӮж•°дёҚиғҪдёәз©ә` };
            const valueResult = evaluateArgumentValue(arg);
            if (!valueResult.success || valueResult.value === undefined) {
              return { success: false, error: valueResult.error ?? `еҮҪж•° ${name} еҸӮж•°и®Ўз®—еӨұиҙҘ` };
            }
            values.push(valueResult.value);
          }

          const fnResult = handler.apply(values);
          if (!Number.isFinite(fnResult)) {
            return { success: false, error: `еҮҪж•° ${name} з»“жһңж— ж•Ҳ` };
          }
          result += normalizeNumberLiteral(fnResult);
          index = closeIndex + 1;
          continue;
        }

        result += char;
        index++;
      }

      return { success: true, expr: result };
    }

    // 1. жӣҝжҚўеҸҳйҮҸ
    // ж”ҜжҢҒеҸҳйҮҸ: $roll.total, $attr, $dc, $mod зӯү,жңӘе®ҡд№үи§Ҷдёә0
    // зү№ж®ҠеӨ„зҗҶ $roll еҜ№иұЎ
    if (context && context.$roll && typeof context.$roll === 'object') {
      const roll = context.$roll as RollResult;
      formula = formula.replace(/\$roll\.total/g, String(roll.total));
      // йў„еӨ„зҗҶ $roll.hasTag('tagName') и°ғз”ЁпјҢеңЁеҸҳйҮҸжӣҝжҚўеүҚе®ҢжҲҗ
      formula = formula.replace(/\$roll\.hasTag\s*\(\s*['"]([^'"]+)['"]\s*\)/gi, (_match, tag) => {
        return (roll.tags ?? []).includes(tag) ? '1' : '0';
      });
    }

    const varPattern = /\$[a-zA-Z_]\w*/g;
    let expr = formula.trim().replace(varPattern, match => {
      const val = context[match];
      return typeof val === 'number' && !isNaN(val) ? String(val) : '0';
    });

    const resolved = resolveFunctions(expr);
    if (!resolved.success || resolved.expr === undefined) {
      return { success: false, error: resolved.error ?? 'еҮҪж•°и§ЈжһҗеӨұиҙҘ' };
    }
    expr = resolved.expr;

    return evaluateExpression(expr);
  };

  /**
   * еҲӨж–ӯжқЎд»¶иЎЁиҫҫејҸжҳҜеҗҰдёәеӨҚжқӮжқЎд»¶ (еҢ…еҗ« && жҲ– ||)
   * @param expr - жқЎд»¶иЎЁиҫҫејҸеӯ—з¬ҰдёІ
   * @returns еҰӮжһңеҢ…еҗ« && жҲ– || иҝ”еӣһ true, еҗҰеҲҷиҝ”еӣһ false
   */
  const isComplexCondition = (expr: string): boolean => {
    return /(\&\&|\|\|)/.test(expr);
  };

  /**
   * иҜ„дј°еӨҡзә§з»“жһң
   * @param outcomes - outcomes ж•°з»„ (дјҡиў«жҺ’еәҸ)
   * @param context - дёҠдёӢж–ҮеҜ№иұЎ {$roll, $attr, $dc, $mod, ...}
   * @returns еҢ№й…Қзҡ„ outcome (еҰӮжһңжүҖжңүжқЎд»¶йғҪдёҚж»Ўи¶і,иҝ”еӣһжңҖдҪҺдјҳе…Ҳзә§зҡ„е…ңеә• outcome)
   */
  const evaluateOutcomes = (outcomes: OutcomeLevel[], context: Record<string, number>) => {
    if (!outcomes || outcomes.length === 0) {
      console.warn('[DICE] outcomes ж•°з»„дёәз©ә,дҪҝз”Ёй»ҳи®ӨеҲӨе®ҡ');
      return { id: 'default', name: 'еҲӨе®ҡз»“жһң', condition: 'true', priority: 99 };
    }
    const sorted = [...outcomes].sort((a, b) => a.priority - b.priority);

    for (const outcome of sorted) {
      try {
        const conditionResult: { success: boolean; value?: number | boolean; error?: string } = evaluateCondition(
          outcome.condition,
          context,
        );
        if (!conditionResult.success) {
          if (conditionResult.error) {
            console.warn(`[DICE] outcome "${outcome.name}" жқЎд»¶иҜ„дј°еӨұиҙҘ:`, conditionResult.error);
          }
          continue;
        }
        const isMatch =
          typeof conditionResult.value === 'number' ? conditionResult.value !== 0 : Boolean(conditionResult.value);
        if (isMatch) {
          return outcome;
        }
      } catch (error) {
        console.warn(`[DICE] outcome "${outcome.name}" жқЎд»¶иҜ„дј°еӨұиҙҘ:`, error);
        continue;
      }
    }

    return sorted[sorted.length - 1];
  };

  // й»ҳи®Өиҫ“еҮәжЁЎжқҝ
  const DEFAULT_OUTPUT_TEMPLATE = `<meta:жЈҖе®ҡз»“жһң>
$outcomeText
е…ғеҸҷдәӢпјҡ$initiator еҸ‘иө·дәҶ $attrName жЈҖе®ҡпјҢ$formula=$rollпјҢеҲӨе®ҡ $conditionExprпјҹ$judgeResultпјҢеҲӨе®ҡдёәгҖҗ$outcomeNameгҖ‘
</meta:жЈҖе®ҡз»“жһң>`;

  // й»ҳи®ӨеҜ№жҠ—жЈҖе®ҡиҫ“еҮәжЁЎжқҝ
  const DEFAULT_CONTEST_OUTPUT_TEMPLATE = `<meta:жЈҖе®ҡз»“жһң>
е…ғеҸҷдәӢпјҡиҝӣиЎҢдәҶдёҖж¬ЎгҖҗ$initiator $initAttrName vs $opponent $oppAttrNameгҖ‘зҡ„еҜ№жҠ—жЈҖе®ҡгҖӮ
$initiator $initAttrNameпјҡ$formula=$initRollпјҢеҲӨе®ҡ $initConditionExprпјҹ$initJudgeResultпјҢеҲӨе®ҡдёәгҖҗ$initSuccessNameгҖ‘пјӣ
$opponent $oppAttrNameпјҡ$formula=$oppRollпјҢеҲӨе®ҡ $oppConditionExprпјҹ$oppJudgeResultпјҢеҲӨе®ҡдёәгҖҗ$oppSuccessNameгҖ‘гҖӮ
жңҖз»Ҳз»“жһңпјҡгҖҗ$winnerгҖ‘
</meta:жЈҖе®ҡз»“жһң>`;

  /**
   * ж јејҸеҢ–иҫ“еҮәжЁЎжқҝ
   * @param template - жЁЎжқҝеӯ—з¬ҰдёІ
   * @param context - еҸҳйҮҸдёҠдёӢж–Ү
   * @returns ж јејҸеҢ–еҗҺзҡ„ж–Үжң¬
   */
  const formatOutputTemplate = (template: string, context: Record<string, string | number | undefined>): string => {
    const missingKeys = new Set<string>();

    // [дҝ®еӨҚ] е…ҲжӣҝжҚўеёҰзӮ№зҡ„еҸҳйҮҸпјҲеҰӮ $roll.totalпјүпјҢеҶҚжӣҝжҚўжҷ®йҖҡеҸҳйҮҸпјҲеҰӮ $rollпјү
    // иҝҷж ·еҸҜд»ҘйҒҝе…Қ $roll.total иў«й”ҷиҜҜең°жӣҝжҚўдёә "3.total"
    let result = template.replace(/\$([a-zA-Z_]\w*\.[a-zA-Z_]\w*)/g, match => {
      const key = match.slice(1); // еҺ»жҺү $ еүҚзјҖпјҢеҫ—еҲ° "roll.total"
      const value = context[key];
      if (value === undefined || value === null) {
        if (!missingKeys.has(key)) {
          missingKeys.add(key);
          console.warn(`[DICE] formatOutputTemplate: жңӘе®ҡд№үеҸҳйҮҸ $${key}`);
        }
        return '';
      }
      return String(value);
    });

    // еҶҚжӣҝжҚўжҷ®йҖҡеҸҳйҮҸ
    result = result.replace(/\$([a-zA-Z_]\w*)(?=\W|$)/g, match => {
      const key = match.slice(1);
      const value = context[key];
      if (value === undefined || value === null) {
        if (!missingKeys.has(key)) {
          missingKeys.add(key);
          console.warn(`[DICE] formatOutputTemplate: жңӘе®ҡд№үеҸҳйҮҸ $${key}`);
        }
        return '';
      }
      return String(value);
    });
    // жё…зҗҶз©әиЎҢпјҡе°Ҷиҝһз»ӯеӨҡдёӘжҚўиЎҢз¬ҰжӣҝжҚўдёәеҚ•дёӘжҚўиЎҢз¬Ұ
    return result.replace(/\n\s*\n/g, '\n');
  };

  /**
   * з”ҹжҲҗеҚ•дёӘеұһжҖ§еҖјпјҢеә”з”ЁиҢғеӣҙйҷҗеҲ¶
   * @param formula е…¬ејҸеӯ—з¬ҰдёІ
   * @param range еҸҜйҖүиҢғеӣҙ [min, max]
   * @param context еҸҳйҮҸдёҠдёӢж–Ү
   * @returns еұһжҖ§еҖј
   */
  const generateAttributeValue = (formula, range, context) => {
    let value = evaluateFormula(formula, context);

    if (range && Array.isArray(range) && range.length === 2) {
      value = Math.max(range[0], Math.min(range[1], value));
    }

    return value;
  };

