    if (n.includes('йҖҡз”Ё') || n.includes('е…ЁеұҖ')) return 'fa-globe-asia';
    if (n.includes('иЈ…еӨҮ') || n.includes('иғҢеҢ…')) return 'fa-briefcase';
    if (n.includes('жҠҖиғҪ') || n.includes('жӯҰйӯӮ')) return 'fa-dragon';
    if (n.includes('е…ізі»') || n.includes('е‘Ёиҫ№')) return 'fa-user-friends';
    if (n.includes('д»»еҠЎ') || n.includes('ж—Ҙеҝ—')) return 'fa-scroll';
    if (n.includes('дәәзү©') || n.includes('е…ій”®дәәзү©')) return 'fa-address-book';
    if (n.includes('жҖ»з»“') || n.includes('еӨ§зәІ')) return 'fa-book-reader';
    if (n.includes('ең°еӣҫзӮ№') || n.includes('дё–з•Ңең°еӣҫ')) return 'fa-map-location-dot';
    if (n.includes('ең°еӣҫе…ғзҙ ') || n.includes('жңәе…і') || n.includes('зәҝзҙў')) return 'fa-bullseye';
    if (n.includes('еҠҝеҠӣ') || n.includes('йҳөиҗҘ')) return 'fa-shield-halved';
