  const stripJsonCommentsAndTrailingCommas = (input: string): string => {
    const text = String(input || '');
    let output = '';
    let inString = false;
    let quote = '';
    let escaped = false;

    for (let index = 0; index < text.length; index++) {
      const char = text[index];
      const next = text[index + 1];

      if (inString) {
        output += char;
        if (escaped) {
          escaped = false;
        } else if (char === '\\') {
          escaped = true;
        } else if (char === quote) {
          inString = false;
          quote = '';
        }
        continue;
      }

      if (char === '"' || char === "'") {
        inString = true;
        quote = char;
        output += char;
        continue;
      }

      if (char === '/' && next === '/') {
        while (index < text.length && text[index] !== '\n') index += 1;
        output += '\n';
        continue;
      }

      if (char === '/' && next === '*') {
        index += 2;
        while (index < text.length && !(text[index] === '*' && text[index + 1] === '/')) index += 1;
        index += 1;
        continue;
      }

      output += char;
    }

    let cleaned = '';
    inString = false;
    quote = '';
    escaped = false;
    for (let index = 0; index < output.length; index++) {
      const char = output[index];
      if (inString) {
        cleaned += char;
        if (escaped) {
          escaped = false;
        } else if (char === '\\') {
          escaped = true;
        } else if (char === quote) {
          inString = false;
          quote = '';
        }
        continue;
      }
      if (char === '"' || char === "'") {
        inString = true;
        quote = char;
        cleaned += char;
        continue;
      }
      if (char === ',') {
        let cursor = index + 1;
        while (cursor < output.length && /\s/.test(output[cursor])) cursor += 1;
        if (output[cursor] === '}' || output[cursor] === ']') continue;
      }
      cleaned += char;
    }

    return cleaned;
  };

