      "type": "йҒ“е…·",

      // qualityпјҡеҝ…еЎ«пјҢеҸӘиғҪжҳҜ жҷ®йҖҡгҖҒдјҳз§ҖгҖҒзЁҖжңүгҖҒеҸІиҜ—гҖҒдј иҜҙгҖҒзҘһиҜқгҖӮ
      "quality": "зЁҖжңү",

      // descriptionпјҡзү©е“ҒжҸҸиҝ°пјҢдјҡеҶҷе…Ҙзү©е“ҒиЎЁпјҢд№ҹдјҡеңЁе•Ҷеә—иҜҰжғ…дёӯеұ•зӨәгҖӮ
      "description": "дёҖжһҡжҖ»иғҪиҗҪеңЁжӯЈйқўзҡ„зЎ¬еёҒгҖӮдҪҝз”ЁеҗҺеҸҜи®©дёӢдёҖж¬Ўжҷ®йҖҡжЈҖе®ҡиҺ·еҫ—иҪ»еҫ®еҘҪиҝҗгҖӮ",

      // poolTagsпјҡеҮәзҺ°еңЁе“ӘдәӣеҘ–жұ гҖӮеҸҜз”ЁеҖјпјҡеҘҮе№»гҖҒдҝ®зңҹгҖҒйғҪеёӮгҖҒж ЎеӣӯгҖҒеҺҶеҸІпјӣеҶҷ е…ЁйғЁ дјҡиҮӘеҠЁеұ•ејҖдёәжүҖжңүеҘ–жұ гҖӮ
      "poolTags": ["е…ЁйғЁ"],

      // weightпјҡеҗҢе“ҒиҙЁеҶ…зҡ„жҠҪеҸ–жқғйҮҚпјҢеҝ…йЎ»еӨ§дәҺ 0гҖӮи¶ҠеӨ§и¶Ҡе®№жҳ“иў«жҠҪеҲ°гҖӮ
      "weight": 1,

