        e.stopPropagation();
        if (isEditingOrder) return;
        const api = getCore().getDB();
        if (api && typeof api.manualUpdate === 'function') {
          try {
            console.log('[DICE]ACU жүӢеҠЁеЎ«иЎЁи§ҰеҸ‘');
            await api.manualUpdate();
          } catch (err) {
            console.error('[DICE]ACU жүӢеҠЁеЎ«иЎЁеӨұиҙҘ:', err);
            const errorMessage = err.message || 'еЎ«иЎЁиҝҮзЁӢдёӯеҮәзҺ°й”ҷиҜҜ';
            if (window.toastr) {
              window.toastr.error(`еЎ«иЎЁеӨұиҙҘ: ${errorMessage}`, 'й”ҷиҜҜ', { timeOut: 5000 });
            } else {
              alert(`еЎ«иЎЁеӨұиҙҘ: ${errorMessage}`);
            }
          }
        } else {
          console.warn('[DICE]ACU manualUpdate API дёҚеҸҜз”Ё');
          if (window.toastr) {
            window.toastr.warning('еҗҺз«Ҝи„ҡжң¬жңӘжҸҗдҫӣ manualUpdate жҺҘеҸЈ', '', { timeOut: 3000 });
          }
        }
