    $('#acu-btn-save-global')
      .off('click')
      .on('click', async function (e) {
        e.stopPropagation();
        if (isEditingOrder) return;
        let dataToSave = null;
        if (hasUnsavedChanges && cachedRawData) {
          dataToSave = cachedRawData;
        } else {
          dataToSave = getTableData();
        }

        if (dataToSave) {
          // 1. гҖҗж ёеҝғдҝ®ж”№гҖ‘жҠҠдёӯй—ҙзҡ„ false ж”№дёә trueпјҢзҰҒжӯўдҝқеӯҳеҗҺйҮҚз»ҳз•Ңйқў
          await saveDataToDatabase(dataToSave, true, true);

          // 2. гҖҗжүӢеҠЁе–„еҗҺгҖ‘еӣ дёәдёҚйҮҚз»ҳдәҶпјҢжҲ‘д»¬йңҖиҰҒжүӢеҠЁжҠҠз•ҢйқўдёҠзҡ„вҖңжңӘдҝқеӯҳвҖқзәўеӯ—еҸҳеӣһжҷ®йҖҡйўңиүІ
          // з§»йҷӨжүҖжңүжүӢеҠЁдҝ®ж”№зҡ„й«ҳдә®зұ»
          $('.acu-highlight-manual').removeClass('acu-highlight-manual');

          // 3. жё…зҗҶеҶ…йғЁзҡ„и„Ҹж•°жҚ®ж Үи®°
          if (window.acuModifiedSet) window.acuModifiedSet.clear();
          hasUnsavedChanges = false;

          // 4. жүӢеҠЁйҮҚзҪ®дҝқеӯҳжҢүй’®зҡ„зҠ¶жҖҒпјҲеҺ»жҺүе‘јеҗёзҒҜпјҢеҸҳеӣһзҒ°иүІпјү
          const $btn = $(this);
          const $icon = $btn.find('i');
          $icon.removeClass('acu-icon-breathe fa-spinner fa-spin').addClass('fa-save');
          $btn.attr('title', 'дҝқеӯҳжүҖжңүдҝ®ж”№').css('color', '');
          $btn.prop('disabled', false);

          // 5. жҸҗзӨәз”ЁжҲ·
        } else {
          if (window.toastr) window.toastr.error('ж— жі•иҺ·еҸ–жңүж•Ҳж•°жҚ®пјҢдҝқеӯҳеӨұиҙҘ');
        }
      });

    const $searchInput = $('.acu-search-input');
    if ($searchInput.length) {
      bindCompositionSafeSearchInput(
        { root: $searchInput },
        {
          delay: 300,
          onCommit: ({ value, selectionStart, selectionEnd }) => {
            const activeTab = getActiveTabState();
            if (activeTab) {
              tableSearchStates[activeTab] = value;
              tablePageStates[activeTab] = 1;
              const isFocus = document.activeElement && document.activeElement.classList.contains('acu-search-input');
              renderInterface();
              if (isFocus) {
                const $newInput = $('.acu-search-input');
                $newInput.focus();
                if ($newInput.length && $newInput[0].setSelectionRange) {
                  try {
                    $newInput[0].setSelectionRange(selectionStart, selectionEnd);
                  } catch (e) {}
                }
              }
            }
          },
        },
      );
    }
    // дәәзү©е…ізі»еӣҫжҢүй’®
    $('#acu-btn-relation-graph')
      .off('click')
      .on('click', function (e) {
        e.preventDefault();
        e.stopPropagation();
        const tableName = $(this).data('table');
        const rawData = cachedRawData || getTableData();
        if (rawData) {
          // NPCиЎЁпјҲйҮҚиҰҒдәәзү©иЎЁ/йҮҚиҰҒи§’иүІиЎЁпјүзӣҙжҺҘдҪҝз”ЁиҜҘиЎЁж•°жҚ®
          if (isNpcTableName(tableName)) {
            for (const key in rawData) {
              const sheet = rawData[key];
              if (sheet?.name === tableName) {
                const tableData = {
                  headers: sheet.content?.[0] || [],
                  rows: sheet.content?.slice(1) || [],
                  key: key,
                };
                showRelationshipGraph(tableData);
                return;
              }
            }
          } else {
            // йқһNPCиЎЁпјҲеҰӮдё»и§’дҝЎжҒҜпјүпјҢйҖҡиҝҮDashboardDataParserжҹҘжүҫNPCиЎЁ
            const allTables = processJsonData(rawData);
            const npcResult = DashboardDataParser.findTable(allTables, 'npc');
            if (npcResult && npcResult.data) {
              showRelationshipGraph(npcResult.data);
              return;
            }
          }
        }
        if (window.toastr) window.toastr.warning('ж— жі•иҺ·еҸ–иЎЁж јж•°жҚ®');
      });
    // иЎЁж јйқўжқҝең°еӣҫеҸҜи§ҶеҢ–жҢүй’®
