    // [ж–°еўһ] жҠҖиғҪеҲ—иЎЁ"дҪҝз”Ё"жҢүй’® - дҪҝз”ЁжҠҖиғҪе№¶иҝӣиЎҢжЈҖе®ҡ
    $('body')
      .off('click.acu_dash_use_skill')
      .on('click.acu_dash_use_skill', '.acu-dash-use-skill-btn', function (e) {
        e.stopPropagation();
        e.preventDefault();
        const skillName = $(this).data('skill') || 'жҠҖиғҪ';

        // жҹҘжүҫиҜҘжҠҖиғҪзҡ„еұһжҖ§еҖјжҲ–зҶҹз»ғеәҰ
        const rawData = cachedRawData || getTableData();
        let checkValue = null;

        if (rawData) {
          // жҹҘжүҫжҠҖиғҪиЎЁ
          for (const key in rawData) {
            const sheet = rawData[key];
            if (!sheet || !sheet.name || !sheet.content) continue;
            if (sheet.name.includes('жҠҖиғҪ') || sheet.name.includes('иғҪеҠӣ')) {
              const headers = sheet.content[0] || [];
              // еҠЁжҖҒжҹҘжүҫеҲ—зҙўеј•
              const nameIdx = headers.findIndex(h => h && (h.includes('еҗҚз§°') || h.includes('жҠҖиғҪеҗҚ'))) || 1;
              const attrValIdx = headers.findIndex(h => h && h.includes('еұһжҖ§еҖј'));
              const profIdx = headers.findIndex(h => h && (h.includes('зҶҹз»ғ') || h.includes('зӯүзә§')));

              for (let i = 1; i < sheet.content.length; i++) {
                const row = sheet.content[i];
                if (row && row[nameIdx === -1 ? 1 : nameIdx] === skillName) {
                  // дјҳе…ҲеҸ–еұһжҖ§еҖј
                  if (attrValIdx > 0 && row[attrValIdx]) {
                    const val = extractNumericValue(row[attrValIdx]);
                    if (val > 0) {
                      checkValue = val;
                      break;
                    }
                  }
                  // еӣһйҖҖеҲ°зҶҹз»ғеәҰ
                  if (profIdx > 0 && row[profIdx]) {
                    const val = extractNumericValue(row[profIdx]);
                    if (val > 0) {
                      checkValue = val;
                      break;
                    }
                  }
                  break;
                }
              }
              if (checkValue !== null) break;
            }
          }
        }

        // е…ҲеЎ«е…ҘдҪҝз”ЁжҠҖиғҪзҡ„ж–Үжң¬
        const promptText = `<user>дҪҝз”Ё${skillName}гҖӮ`;
        smartInsertToTextarea(promptText, 'action');

        // еҰӮжһңжңүжңүж•Ҳж•°еҖјпјҢжү“ејҖжҺ·йӘ°йқўжқҝиҝӣиЎҢжЈҖе®ҡ
        if (checkValue !== null && checkValue > 0) {
          showDicePanel({
            attrValue: checkValue,
            targetValue: null,
            targetName: skillName,
            initiatorName: '<user>',
          });
        } else {
          // жІЎжңүжңүж•Ҳж•°еҖјпјҢеҸӘиҒҡз„Ұиҫ“е…ҘжЎҶ
          $('#send_textarea').focus();
        }
      });
    // [ж–°еўһ] иҝӣиЎҢдёӯд»»еҠЎ"иҝҪиёӘ"жҢүй’®
    $('body')
